import React, { useState, useEffect, useCallback, useRef } from 'react';
import api from '../utils/axiosConfig';
import { useAuth } from '../context/AuthContext';
import ProductList from '../ProductList';
import ProductForm from '../ProductForm';
import { Plus, Search, Filter, ChevronLeft, ChevronRight, AlertCircle, RefreshCw } from 'lucide-react';
import { toast } from 'react-hot-toast';

const LIMIT = 20;

const Products = () => {
    const { user } = useAuth();

    // ── Estado de datos ──────────────────────────────────────────
    const [products, setProducts] = useState([]);
    const [total, setTotal] = useState(0);
    const [totalPages, setTotalPages] = useState(1);
    const [currentPage, setCurrentPage] = useState(1);

    // ── UI state ─────────────────────────────────────────────────
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [showModal, setShowModal] = useState(false);
    const [editingProduct, setEditingProduct] = useState(null);

    // ── Filtros ──────────────────────────────────────────────────
    const [searchTerm, setSearchTerm] = useState('');
    const [debouncedSearch, setDebouncedSearch] = useState('');
    const [categoryFilter, setCategoryFilter] = useState('');

    // Debounce de búsqueda — 400ms
    const debounceRef = useRef(null);
    const handleSearchChange = (e) => {
        const val = e.target.value;
        setSearchTerm(val);
        setCurrentPage(1);
        clearTimeout(debounceRef.current);
        debounceRef.current = setTimeout(() => setDebouncedSearch(val), 400);
    };

    // ── Fetch paginado ───────────────────────────────────────────
    const fetchProducts = useCallback(async () => {
        setLoading(true);
        setError(null);
        try {
            const params = new URLSearchParams({
                page: currentPage,
                limit: LIMIT,
                ...(debouncedSearch && { search: debouncedSearch }),
                ...(categoryFilter && { categoria: categoryFilter }),
            });
            const res = await api.get(`/productos?${params}`);

            // Si la respuesta viene paginada (tiene .data) o sin paginar (array directo)
            if (Array.isArray(res.data)) {
                setProducts(res.data);
                setTotal(res.data.length);
                setTotalPages(1);
            } else {
                setProducts(res.data.data || []);
                setTotal(res.data.total || 0);
                setTotalPages(res.data.totalPages || 1);
            }
        } catch (err) {
            const msg = err.response?.data?.error || 'Error al cargar los productos';
            setError(msg);
            toast.error(msg);
        } finally {
            setLoading(false);
        }
    }, [currentPage, debouncedSearch, categoryFilter]);

    useEffect(() => {
        fetchProducts();
    }, [fetchProducts]);

    // ── CRUD ─────────────────────────────────────────────────────
    const addProduct = async (product) => {
        try {
            await api.post('/productos/crear', product);
            setShowModal(false);
            toast.success('Producto creado exitosamente');
            fetchProducts();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al agregar producto');
        }
    };

    const updateProduct = async (id, productData) => {
        try {
            await api.put(`/productos/editar/${id}`, productData);
            setShowModal(false);
            setEditingProduct(null);
            toast.success('Producto actualizado exitosamente');
            fetchProducts();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al actualizar producto');
        }
    };

    const deleteProduct = async (id) => {
        if (!window.confirm('¿Estás seguro de eliminar este producto permanentemente?')) return;
        try {
            await api.delete(`/productos/eliminar/${id}`);
            toast.success('Producto eliminado exitosamente');
            // Si era la última en la página, retroceder
            if (products.length === 1 && currentPage > 1) {
                setCurrentPage(p => p - 1);
            } else {
                fetchProducts();
            }
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al eliminar producto');
        }
    };

    const openCreateModal = () => { setEditingProduct(null); setShowModal(true); };
    const openEditModal = (product) => { setEditingProduct(product); setShowModal(true); };

    // ── Render ────────────────────────────────────────────────────
    return (
        <div className="space-y-6">
            {/* Header */}
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-gray-900">Productos</h1>
                    {!loading && (
                        <p className="text-sm text-gray-500 mt-0.5">{total} productos en total</p>
                    )}
                </div>
                {user?.rol?.toLowerCase() === 'admin' && (
                    <button
                        onClick={openCreateModal}
                        className="flex items-center px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-md hover:bg-indigo-700 transition"
                    >
                        <Plus size={16} className="mr-2" />
                        Nuevo Producto
                    </button>
                )}
            </div>

            {/* Filtros */}
            <div className="bg-white p-4 shadow-sm rounded-lg border border-gray-200 flex flex-col sm:flex-row gap-4">
                <div className="relative flex-1">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        placeholder="Buscar por nombre, SKU o descripción..."
                        className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                        value={searchTerm}
                        onChange={handleSearchChange}
                    />
                </div>
                <div className="relative sm:w-56">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Filter className="h-4 w-4 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        placeholder="Filtrar por categoría..."
                        className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white placeholder-gray-500 focus:outline-none focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                        value={categoryFilter}
                        onChange={(e) => { setCategoryFilter(e.target.value); setCurrentPage(1); }}
                    />
                </div>
            </div>

            {/* Estado de carga */}
            {loading && (
                <div className="bg-white shadow-sm rounded-lg border border-gray-200 flex items-center justify-center py-20">
                    <div className="flex flex-col items-center gap-3 text-gray-400">
                        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                        <p className="text-sm">Cargando productos...</p>
                    </div>
                </div>
            )}

            {/* Estado de error */}
            {!loading && error && (
                <div className="bg-red-50 border border-red-200 rounded-lg p-6 flex flex-col items-center gap-3">
                    <AlertCircle className="text-red-400" size={32} />
                    <p className="text-red-700 font-medium">{error}</p>
                    <button
                        onClick={fetchProducts}
                        className="flex items-center gap-2 px-4 py-2 bg-red-100 text-red-700 rounded-md hover:bg-red-200 text-sm font-medium transition"
                    >
                        <RefreshCw size={14} /> Reintentar
                    </button>
                </div>
            )}

            {/* Tabla */}
            {!loading && !error && (
                <div className="bg-white shadow-sm rounded-lg border border-gray-200">
                    <ProductList
                        products={products}
                        onEdit={openEditModal}
                        onDelete={deleteProduct}
                        userRole={user?.rol}
                    />

                    {/* Paginación */}
                    {totalPages > 1 && (
                        <div className="px-6 py-4 border-t border-gray-200 flex items-center justify-between">
                            <p className="text-sm text-gray-500">
                                Página <span className="font-medium">{currentPage}</span> de{' '}
                                <span className="font-medium">{totalPages}</span>
                                {' '}— {total} productos
                            </p>
                            <div className="flex items-center gap-2">
                                <button
                                    onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                                    disabled={currentPage === 1}
                                    className="p-2 rounded-md border border-gray-300 disabled:opacity-40 disabled:cursor-not-allowed hover:bg-gray-50 transition"
                                >
                                    <ChevronLeft size={16} />
                                </button>

                                {/* Números de página */}
                                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                                    let pageNum;
                                    if (totalPages <= 5) {
                                        pageNum = i + 1;
                                    } else if (currentPage <= 3) {
                                        pageNum = i + 1;
                                    } else if (currentPage >= totalPages - 2) {
                                        pageNum = totalPages - 4 + i;
                                    } else {
                                        pageNum = currentPage - 2 + i;
                                    }
                                    return (
                                        <button
                                            key={pageNum}
                                            onClick={() => setCurrentPage(pageNum)}
                                            className={`w-9 h-9 rounded-md text-sm font-medium transition ${currentPage === pageNum
                                                    ? 'bg-indigo-600 text-white'
                                                    : 'border border-gray-300 text-gray-700 hover:bg-gray-50'
                                                }`}
                                        >
                                            {pageNum}
                                        </button>
                                    );
                                })}

                                <button
                                    onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                                    disabled={currentPage === totalPages}
                                    className="p-2 rounded-md border border-gray-300 disabled:opacity-40 disabled:cursor-not-allowed hover:bg-gray-50 transition"
                                >
                                    <ChevronRight size={16} />
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            )}

            {/* Modal Crear/Editar */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center overflow-x-hidden overflow-y-auto outline-none focus:outline-none bg-black bg-opacity-50">
                    <div className="relative w-full max-w-md mx-auto my-6">
                        <div className="relative flex flex-col w-full bg-white border-0 rounded-lg shadow-lg outline-none focus:outline-none">
                            <div className="flex items-start justify-between p-5 border-b border-solid border-gray-200 rounded-t">
                                <h3 className="text-xl font-semibold">
                                    {editingProduct ? 'Editar Producto' : 'Agregar Nuevo Producto'}
                                </h3>
                                <button
                                    className="p-1 ml-auto bg-transparent border-0 text-black float-right text-3xl leading-none font-semibold outline-none focus:outline-none"
                                    onClick={() => setShowModal(false)}
                                >
                                    <span className="text-gray-400 block w-6 h-6 text-2xl -mt-1 hover:text-gray-600">×</span>
                                </button>
                            </div>
                            <div className="relative p-6 flex-auto">
                                <ProductForm
                                    onAdd={addProduct}
                                    onUpdate={updateProduct}
                                    isModal={true}
                                    closeModal={() => setShowModal(false)}
                                    initialData={editingProduct}
                                />
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Products;
