import { Edit, Trash2 } from 'lucide-react';

const ProductList = ({ products, onEdit, onDelete, userRole }) => {
  const isAdmin = userRole?.toLowerCase() === 'admin';
  return (
    <div className="overflow-x-auto">
      <table className="min-w-full divide-y divide-gray-200">
        <thead className="bg-gray-50">
          <tr>
            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">SKU</th>
            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Nombre</th>
            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Categoría</th>
            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Descripción</th>
            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Precio</th>
            <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Stock</th>
            {isAdmin && (
              <th className="px-4 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Acciones</th>
            )}
          </tr>
        </thead>
        <tbody className="bg-white divide-y divide-gray-200">
          {products.map((p) => (
            <tr key={p.id} className="hover:bg-gray-50 transition-colors">
              {/* SKU */}
              <td className="px-4 py-4 whitespace-nowrap">
                {p.sku ? (
                  <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-mono font-bold bg-gray-100 text-gray-700 border border-gray-200">
                    {p.sku}
                  </span>
                ) : (
                  <span className="text-gray-300 text-xs italic">—</span>
                )}
              </td>
              {/* Nombre */}
              <td className="px-4 py-4 whitespace-nowrap text-sm font-semibold text-gray-900">{p.nombre}</td>
              {/* Categoría */}
              <td className="px-4 py-4 whitespace-nowrap text-sm text-gray-500">
                {p.categoria ? (
                  <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-700">
                    {p.categoria}
                  </span>
                ) : (
                  <span className="text-gray-300 italic text-xs">Sin categoría</span>
                )}
              </td>
              {/* Descripción */}
              <td className="px-4 py-4 text-sm text-gray-500 max-w-xs truncate">{p.descripcion || '—'}</td>
              {/* Precio */}
              <td className="px-4 py-4 whitespace-nowrap text-sm font-bold text-gray-800">${Number(p.precio).toFixed(2)}</td>
              {/* Stock */}
              <td className="px-4 py-4 whitespace-nowrap">
                <span className={`px-2 inline-flex text-xs leading-5 font-bold rounded-full ${p.stock === 0
                    ? 'bg-red-100 text-red-800'
                    : p.stock <= 5
                      ? 'bg-amber-100 text-amber-800'
                      : 'bg-green-100 text-green-800'
                  }`}>
                  {p.stock === 0 ? 'Agotado' : p.stock}
                </span>
              </td>
              {/* Acciones */}
              {isAdmin && (
                <td className="px-4 py-4 whitespace-nowrap text-right text-sm font-medium">
                  <div className="flex justify-end space-x-2">
                    <button
                      onClick={() => onEdit(p)}
                      className="text-indigo-600 hover:text-indigo-900 p-1 rounded hover:bg-indigo-50"
                      title="Editar producto"
                    >
                      <Edit size={16} />
                    </button>
                    <button
                      onClick={() => onDelete(p.id)}
                      className="text-red-600 hover:text-red-900 p-1 rounded hover:bg-red-50"
                      title="Eliminar producto"
                    >
                      <Trash2 size={16} />
                    </button>
                  </div>
                </td>
              )}
            </tr>
          ))}
        </tbody>
      </table>
      {products.length === 0 && (
        <div className="text-center py-10 text-gray-500 text-sm">
          No hay productos disponibles.
        </div>
      )}
    </div>
  );
};

export default ProductList;
