import React, { useState, useEffect } from 'react';
import api from '../utils/axiosConfig';
import { useAuth } from '../context/AuthContext';
import { Plus, ArrowDownRight, ArrowUpRight } from 'lucide-react';
import { toast } from 'react-hot-toast';

const Movements = () => {
    const { token } = useAuth();
    const [movements, setMovements] = useState([]);
    const [products, setProducts] = useState([]);
    const [showModal, setShowModal] = useState(false);

    // Form state
    const [formData, setFormData] = useState({
        productoId: '',
        tipo: 'entrada',
        cantidad: ''
    });

    useEffect(() => {
        if (token) {
            fetchMovements();
            fetchProducts();
        }
    }, [token]);

    const fetchMovements = async () => {
        try {
            const res = await api.get('/movimientos');
            setMovements(res.data);
        } catch (err) {
            console.error('Error al cargar movimientos:', err);
        }
    };

    const fetchProducts = async () => {
        try {
            const res = await api.get('/productos');
            setProducts(res.data);
        } catch (err) {
            console.error('Error al cargar productos:', err);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            await api.post('/movimientos/registrar', formData);
            setShowModal(false);
            setFormData({ productoId: '', tipo: 'entrada', cantidad: '' });
            fetchMovements();
            toast.success('Movimiento registrado con éxito');
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al registrar movimiento');
        }
    };

    const getProductName = (id) => {
        const prod = products.find(p => p.id === id);
        return prod ? prod.nombre : `ID: ${id}`;
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h1 className="text-2xl font-bold text-gray-900">Historial de Movimientos</h1>
                <button
                    onClick={() => setShowModal(true)}
                    className="flex items-center px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-md hover:bg-indigo-700 transition"
                >
                    <Plus size={16} className="mr-2" />
                    Registrar Movimiento
                </button>
            </div>

            <div className="bg-white shadow-sm rounded-lg border border-gray-200 overflow-hidden">
                <table className="min-w-full divide-y divide-gray-200">
                    <thead className="bg-gray-50">
                        <tr>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Fecha</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Producto</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Tipo</th>
                            <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Cantidad</th>
                        </tr>
                    </thead>
                    <tbody className="bg-white divide-y divide-gray-200">
                        {movements.map((mov) => (
                            <tr key={mov.id} className="hover:bg-gray-50">
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                                    {new Date(mov.fecha).toLocaleString()}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">
                                    {getProductName(mov.productoId)}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm">
                                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full font-medium ${mov.tipo.toLowerCase() === 'entrada'
                                        ? 'bg-green-100 text-green-800'
                                        : 'bg-red-100 text-red-800'
                                        }`}>
                                        {mov.tipo.toLowerCase() === 'entrada' ? <ArrowDownRight size={14} className="mr-1" /> : <ArrowUpRight size={14} className="mr-1" />}
                                        {mov.tipo.toUpperCase()}
                                    </span>
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-right font-medium text-gray-900">
                                    {mov.tipo.toLowerCase() === 'entrada' ? '+' : '-'}{mov.cantidad}
                                </td>
                            </tr>
                        ))}
                        {movements.length === 0 && (
                            <tr>
                                <td colSpan="4" className="px-6 py-8 text-center text-sm text-gray-500">
                                    No hay movimientos registrados.
                                </td>
                            </tr>
                        )}
                    </tbody>
                </table>
            </div>

            {/* Modal para Registrar Movimiento */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center overflow-x-hidden overflow-y-auto outline-none focus:outline-none bg-black bg-opacity-50">
                    <div className="relative w-full max-w-md mx-auto my-6">
                        <div className="relative flex flex-col w-full bg-white border-0 rounded-lg shadow-lg outline-none focus:outline-none">
                            <div className="flex items-start justify-between p-5 border-b border-solid border-gray-200 rounded-t">
                                <h3 className="text-xl font-semibold">Registrar Movimiento</h3>
                                <button
                                    className="p-1 ml-auto bg-transparent border-0 text-gray-400 float-right text-3xl leading-none font-semibold outline-none focus:outline-none hover:text-gray-600"
                                    onClick={() => setShowModal(false)}
                                >
                                    <span className="block w-6 h-6 text-2xl -mt-1">×</span>
                                </button>
                            </div>
                            <div className="relative p-6 flex-auto">
                                <form onSubmit={handleSubmit} className="space-y-4">
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700">Producto</label>
                                        <select
                                            required
                                            className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
                                            value={formData.productoId}
                                            onChange={(e) => setFormData({ ...formData, productoId: e.target.value })}
                                        >
                                            <option value="">Seleccione un producto</option>
                                            {products.map(p => (
                                                <option key={p.id} value={p.id}>{p.nombre} (Stock actual: {p.stock})</option>
                                            ))}
                                        </select>
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700">Tipo de Movimiento</label>
                                        <div className="mt-2 flex gap-4">
                                            <label className="inline-flex items-center">
                                                <input
                                                    type="radio"
                                                    className="form-radio text-indigo-600"
                                                    name="tipo"
                                                    value="entrada"
                                                    checked={formData.tipo === 'entrada'}
                                                    onChange={(e) => setFormData({ ...formData, tipo: e.target.value })}
                                                />
                                                <span className="ml-2">Entrada</span>
                                            </label>
                                            <label className="inline-flex items-center">
                                                <input
                                                    type="radio"
                                                    className="form-radio text-indigo-600"
                                                    name="tipo"
                                                    value="salida"
                                                    checked={formData.tipo === 'salida'}
                                                    onChange={(e) => setFormData({ ...formData, tipo: e.target.value })}
                                                />
                                                <span className="ml-2">Salida</span>
                                            </label>
                                        </div>
                                    </div>
                                    <div>
                                        <label className="block text-sm font-medium text-gray-700">Cantidad</label>
                                        <input
                                            type="number"
                                            required
                                            min="1"
                                            className="mt-1 appearance-none block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm placeholder-gray-400 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                                            value={formData.cantidad}
                                            onChange={(e) => setFormData({ ...formData, cantidad: e.target.value })}
                                        />
                                    </div>
                                    <div className="pt-4 flex items-center justify-end border-t border-solid border-gray-200">
                                        <button
                                            type="button"
                                            className="text-gray-500 background-transparent font-bold px-6 py-2 text-sm outline-none focus:outline-none mr-1 mb-1 ease-linear transition-all duration-150 hover:text-gray-700"
                                            onClick={() => setShowModal(false)}
                                        >
                                            Cancelar
                                        </button>
                                        <button
                                            type="submit"
                                            className="bg-indigo-600 text-white active:bg-indigo-700 font-bold uppercase text-sm px-6 py-3 rounded shadow hover:shadow-lg outline-none focus:outline-none mr-1 mb-1 ease-linear transition-all duration-150"
                                        >
                                            Guardar
                                        </button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Movements;
