import React, { useState, useEffect, useCallback, useMemo } from 'react';
import api from '../utils/axiosConfig';
import { useAuth } from '../context/AuthContext';
import {
    Users as UsersIcon, Shield, ShoppingBag, Trash2, Plus,
    Eye, EyeOff, AlertCircle, CheckCircle, Building2,
    UserCheck, UserX, RefreshCw, ChevronDown, X,
    Edit3, Key, Search, MoreVertical, Check
} from 'lucide-react';
import { toast } from 'react-hot-toast';

// ─── Constantes ───────────────────────────────────────────────────────────────
const ROL_CONFIG = {
    admin: { label: 'Admin', color: 'bg-purple-100 text-purple-800', icon: Shield },
    vendedor: { label: 'Vendedor', color: 'bg-gray-100 text-gray-700', icon: ShoppingBag },
};

const TABS = [
    { id: 'miembros', label: 'Miembros', icon: UsersIcon },
    { id: 'accesos', label: 'Acceso Global', icon: Building2 },
];

const inputCls = 'w-full px-3 py-2 border border-gray-300 rounded-lg text-sm focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition disabled:bg-gray-50 disabled:text-gray-500';

// ─── Sub-componentes ──────────────────────────────────────────────────────────

const RolBadge = ({ rol }) => {
    const cfg = ROL_CONFIG[rol] || { label: rol, color: 'bg-gray-100 text-gray-700', icon: Shield };
    const Icon = cfg.icon;
    return (
        <span className={`inline-flex items-center gap-1 px-2.5 py-0.5 rounded-full text-xs font-medium ${cfg.color}`}>
            <Icon size={11} /> {cfg.label}
        </span>
    );
};

// Modal de Confirmación genérico (reemplaza window.confirm)
const ConfirmModal = ({ show, title, message, onConfirm, onCancel, type = 'danger' }) => {
    if (!show) return null;
    const btnCls = type === 'danger' ? 'bg-red-600 hover:bg-red-700' : 'bg-indigo-600 hover:bg-indigo-700';
    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
            <div className="bg-white rounded-2xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-200">
                <div className="p-6">
                    <h3 className="text-lg font-bold text-gray-900 mb-2">{title}</h3>
                    <p className="text-sm text-gray-500">{message}</p>
                </div>
                <div className="bg-gray-50 px-6 py-4 flex flex-row-reverse gap-3">
                    <button onClick={onConfirm} className={`px-4 py-2 text-white text-sm font-medium rounded-lg transition ${btnCls}`}>
                        Confirmar
                    </button>
                    <button onClick={onCancel} className="px-4 py-2 text-gray-600 hover:text-gray-800 text-sm font-medium transition">
                        Cancelar
                    </button>
                </div>
            </div>
        </div>
    );
};

// ─── Componente Principal ─────────────────────────────────────────────────────

const Users = () => {
    const { user: me } = useAuth();
    const isAdmin = me?.rol?.toLowerCase() === 'admin';

    // Estados de datos
    const [tab, setTab] = useState('miembros');
    const [users, setUsers] = useState([]);
    const [globalUsers, setGlobalUsers] = useState([]);
    const [empresasDisponibles, setEmpresasDisponibles] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');

    // Estados de Modales
    const [modalUser, setModalUser] = useState(null); // { type: 'create' | 'edit' | 'reset' | 'access', user?: obj }
    const [confirmAction, setConfirmAction] = useState(null); // { title, message, onConfirm, type }

    // Estados de formularios
    const [formData, setFormData] = useState({ nombre: '', email: '', password: '', rol: 'vendedor' });
    const [accesoData, setAccesoData] = useState({ empresa_id: '', rol: 'vendedor' });
    const [submitting, setSubmitting] = useState(false);
    const [showPassword, setShowPassword] = useState(false);

    // ── Carga de Datos ───────────────────────────────────────────────

    const fetchUsers = useCallback(async () => {
        setLoading(true);
        try {
            const res = await api.get('/auth');
            setUsers(res.data);
        } catch (err) {
            toast.error('Error al cargar usuarios');
        } finally {
            setLoading(false);
        }
    }, []);

    const fetchEmpresas = useCallback(async () => {
        try {
            const res = await api.get('/auth/empresas-disponibles');
            setEmpresasDisponibles(res.data);
        } catch (err) {
            console.error('Error cargando empresas:', err);
        }
    }, []);

    const fetchGlobalUsers = useCallback(async () => {
        if (!isAdmin) return;
        try {
            const res = await api.get('/auth/global');
            setGlobalUsers(res.data);
        } catch (err) {
            console.error('Error cargando usuarios globales:', err);
        }
    }, [isAdmin]);

    useEffect(() => {
        fetchUsers();
        if (isAdmin) {
            fetchEmpresas();
            fetchGlobalUsers();
        }
    }, [fetchUsers, fetchEmpresas, fetchGlobalUsers, isAdmin]);

    // Filtrado local
    const filteredUsers = useMemo(() => {
        const source = tab === 'miembros' ? users : globalUsers;
        if (!searchTerm) return source;
        const low = searchTerm.toLowerCase();
        return source.filter(u =>
            (u.nombre && String(u.nombre).toLowerCase().includes(low)) ||
            (u.email && String(u.email).toLowerCase().includes(low))
        );
    }, [users, globalUsers, tab, searchTerm]);

    // ── Handlers ───────────────────────────────────────────────────

    const closeModals = () => {
        setModalUser(null);
        setFormData({ nombre: '', email: '', password: '', rol: 'vendedor' });
        setAccesoData({ empresa_id: '', rol: 'vendedor' });
        setShowPassword(false);
    };

    const handleCreateUser = async (e) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            await api.post('/auth/users', formData);
            toast.success('Usuario creado exitosamente');
            closeModals();
            fetchUsers();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al crear usuario');
        } finally {
            setSubmitting(false);
        }
    };

    const handleEditUser = async (e) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            await api.put(`/auth/${modalUser.user.id}`, { nombre: formData.nombre, email: formData.email });
            toast.success('Perfil actualizado');
            closeModals();
            fetchUsers();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al actualizar');
        } finally {
            setSubmitting(false);
        }
    };

    const handleResetPassword = async (e) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            await api.post(`/auth/${modalUser.user.id}/reset-password`, { nuevaPassword: formData.password });
            toast.success('Contraseña reestablecida correctamente');
            closeModals();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al reestablecer');
        } finally {
            setSubmitting(false);
        }
    };

    const handleRoleChange = async (userId, newRole) => {
        const u = users.find(x => x.id === userId);
        setConfirmAction({
            title: 'Cambiar Rol',
            message: `¿Estás seguro de cambiar el rol de ${u.nombre} a ${ROL_CONFIG[newRole].label}?`,
            type: 'info',
            onConfirm: async () => {
                try {
                    await api.put(`/auth/${userId}/rol`, { rol: newRole });
                    toast.success('Rol actualizado');
                    fetchUsers();
                } catch (err) {
                    toast.error(err.response?.data?.error || 'Error al actualizar');
                }
                setConfirmAction(null);
            }
        });
    };

    const handleRevocar = async (userId) => {
        const u = users.find(x => x.id === userId);
        setConfirmAction({
            title: 'Revocar Acceso',
            message: `¿Deseas quitar el acceso de ${u.nombre} a esta empresa? La cuenta seguirá existiendo en el sistema.`,
            type: 'danger',
            onConfirm: async () => {
                try {
                    await api.delete(`/auth/${userId}`);
                    toast.success('Acceso revocado');
                    fetchUsers();
                } catch (err) {
                    toast.error(err.response?.data?.error || 'Error al revocar');
                }
                setConfirmAction(null);
            }
        });
    };

    const handleDarAcceso = async (e) => {
        e.preventDefault();
        setSubmitting(true);
        try {
            await api.post(`/auth/${modalUser.user.id}/empresas`, accesoData);
            toast.success('Acceso otorgado correctamente');
            closeModals();
            fetchUsers(); // Actualiza conteo de empresas
            fetchGlobalUsers(); // Actualiza tabla global
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al otorgar acceso');
        } finally {
            setSubmitting(false);
        }
    };

    // ── Agrupación de datos para Acceso Global ─────────────────────
    const groupedGlobalUsers = useMemo(() => {
        const groups = {};
        globalUsers.forEach(u => {
            if (!groups[u.id]) {
                groups[u.id] = {
                    id: u.id,
                    nombre: u.nombre,
                    email: u.email,
                    membresias: []
                };
            }
            groups[u.id].membresias.push({
                empresa_id: u.empresa_id,
                empresa_nombre: u.empresa_nombre,
                rol: u.rol,
                fecha_union: u.fecha_union
            });
        });
        return Object.values(groups);
    }, [globalUsers]);

    // ── Render Helpers ─────────────────────────────────────────────

    const ActionButton = ({ icon: Icon, onClick, title, color = 'text-gray-400 hover:text-indigo-600', bg = 'hover:bg-indigo-50' }) => (
        <button
            onClick={onClick}
            title={title}
            className={`p-2 rounded-lg transition-all ${color} ${bg}`}
        >
            <Icon size={16} />
        </button>
    );

    // ── Render Principal ───────────────────────────────────────────

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20">

            {/* Header / Search */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div className="flex items-center gap-3">
                    <div className="bg-indigo-600 p-2.5 rounded-xl text-white shadow-lg shadow-indigo-200">
                        <UsersIcon size={24} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-bold text-gray-900">Gestión de Usuarios</h1>
                        <p className="text-sm text-gray-500">Control de miembros y accesos multi-empresa</p>
                    </div>
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                        <input
                            type="text"
                            placeholder="Buscar por nombre o email..."
                            className="w-full pl-10 pr-4 py-2 bg-white border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none transition"
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                    </div>
                    {isAdmin && (
                        <button
                            onClick={() => { setModalUser({ type: 'create' }); setFormData({ nombre: '', email: '', password: '', rol: 'vendedor' }); }}
                            className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 text-white text-sm font-semibold rounded-xl hover:bg-indigo-700 transition shadow-md hover:shadow-lg active:scale-95"
                        >
                            <Plus size={18} /> <span className="hidden sm:inline">Nuevo Usuario</span>
                        </button>
                    )}
                </div>
            </div>

            {/* Tabs & Content */}
            <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
                <div className="bg-gray-50/50 px-6 pt-2 border-b border-gray-100 flex items-center justify-between">
                    <nav className="flex gap-8">
                        {TABS.map(t => {
                            const Icon = t.icon;
                            const active = tab === t.id;
                            return (
                                <button
                                    key={t.id}
                                    onClick={() => setTab(t.id)}
                                    className={`flex items-center gap-2.5 py-4 text-sm font-semibold border-b-2 transition-all relative ${active
                                        ? 'text-indigo-600 border-indigo-600'
                                        : 'text-gray-400 border-transparent hover:text-gray-600'
                                        }`}
                                >
                                    <Icon size={18} />
                                    {t.label}
                                    {active && <span className="absolute -bottom-[2px] left-0 right-0 h-[2px] bg-indigo-600 rounded-full animate-in fade-in duration-300"></span>}
                                </button>
                            );
                        })}
                    </nav>
                    <button
                        onClick={() => { fetchUsers(); if (isAdmin) fetchGlobalUsers(); }}
                        className="p-2 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"
                        title="Refrescar datos"
                    >
                        <RefreshCw size={18} className={loading ? 'animate-spin' : ''} />
                    </button>
                </div>

                {loading ? (
                    <div className="flex flex-col items-center justify-center py-24 gap-4">
                        <div className="w-12 h-12 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                        <p className="text-sm font-medium text-gray-400 animate-pulse">Sincronizando miembros...</p>
                    </div>
                ) : (tab === 'miembros' ? users : groupedGlobalUsers).length === 0 ? (
                    <div className="flex flex-col items-center justify-center py-32 text-gray-400">
                        <UsersIcon size={64} className="mb-4 opacity-10" />
                        <p className="text-lg font-medium">No se encontraron resultados</p>
                        <p className="text-sm">Probá con otros términos de búsqueda.</p>
                    </div>
                ) : (
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead>
                                <tr className="bg-gray-50/20">
                                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-widest">Usuario</th>
                                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-widest">
                                        {tab === 'miembros' ? 'Membresía en esta Empresa' : 'Empresas Vinculadas'}
                                    </th>
                                    <th className="px-6 py-4 text-xs font-bold text-gray-400 uppercase tracking-widest">Estado</th>
                                    <th className="px-6 py-4 text-right text-xs font-bold text-gray-400 uppercase tracking-widest">Acciones</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-50">
                                {(tab === 'miembros' ? users : groupedGlobalUsers).map(u => (
                                    <tr key={u.id} className="hover:bg-indigo-50/20 transition-colors group">
                                        <td className="px-6 py-5 whitespace-nowrap align-top">
                                            <div className="flex items-center gap-4">
                                                <div className="w-11 h-11 rounded-2xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-lg font-bold text-white shadow-sm ring-4 ring-indigo-50 group-hover:ring-indigo-100 transition-all">
                                                    {u.nombre?.charAt(0).toUpperCase()}
                                                </div>
                                                <div>
                                                    <div className="flex items-center gap-2">
                                                        <span className="font-bold text-gray-900 group-hover:text-indigo-700 transition-colors">{u.nombre}</span>
                                                        {u.id === me?.id && (
                                                            <span className="text-[10px] font-black uppercase tracking-tighter bg-indigo-100 text-indigo-700 px-1.5 py-0.5 rounded">Tú</span>
                                                        )}
                                                    </div>
                                                    <span className="text-xs text-gray-500 font-medium block mt-0.5">{u.email}</span>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-5">
                                            {tab === 'miembros' ? (
                                                <div className="flex flex-col gap-1.5">
                                                    {isAdmin && u.id !== me?.id ? (
                                                        <div className="relative w-max">
                                                            <select
                                                                value={u.rol}
                                                                onChange={(e) => handleRoleChange(u.id, e.target.value)}
                                                                className={`appearance-none pr-8 pl-3 py-1 text-xs font-bold rounded-full cursor-pointer focus:outline-none focus:ring-2 focus:ring-indigo-500 ring-offset-1 transition shadow-sm ${ROL_CONFIG[u.rol]?.color || 'bg-gray-100'}`}
                                                            >
                                                                {Object.entries(ROL_CONFIG).map(([val, cfg]) => (
                                                                    <option key={val} value={val}>{cfg.label}</option>
                                                                ))}
                                                            </select>
                                                            <ChevronDown size={12} className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none opacity-60" />
                                                        </div>
                                                    ) : (
                                                        <RolBadge rol={u.rol} />
                                                    )}
                                                    {u.num_empresas > 1 && (
                                                        <div className="flex items-center gap-1.5 text-[10px] font-bold text-indigo-500 bg-indigo-50 w-max px-2 py-0.5 rounded-full border border-indigo-100">
                                                            <Building2 size={10} /> +{u.num_empresas - 1} empresas adicionales
                                                        </div>
                                                    )}
                                                </div>
                                            ) : (
                                                <div className="space-y-2">
                                                    {u.membresias.map(m => (
                                                        <div key={m.empresa_id} className="flex items-center gap-2 bg-gray-50 border border-gray-100 rounded-xl p-2 group/mb transition-all hover:border-indigo-200 hover:bg-indigo-50/30">
                                                            <div className="w-7 h-7 bg-white rounded-lg flex items-center justify-center text-indigo-600 border border-gray-100">
                                                                <Building2 size={14} />
                                                            </div>
                                                            <div className="flex-1 min-w-0">
                                                                <p className="text-xs font-bold text-gray-700 truncate">{m.empresa_nombre}</p>
                                                                <div className="flex items-center gap-2 mt-0.5">
                                                                    <span className={`text-[9px] font-black uppercase tracking-wider px-1 rounded flex items-center gap-1 ${ROL_CONFIG[m.rol]?.color || 'bg-gray-100'}`}>
                                                                        {m.rol}
                                                                    </span>
                                                                    <span className="text-[9px] text-gray-400">Unido: {new Date(m.fecha_union).toLocaleDateString('es-AR')}</span>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            )}
                                        </td>
                                        <td className="px-6 py-5 whitespace-nowrap align-top">
                                            <div className="flex flex-col">
                                                <div className="flex items-center gap-1.5 text-xs text-gray-700 font-bold">
                                                    <CheckCircle size={14} className="text-green-500" /> Miembro Activo
                                                </div>
                                                <span className="text-[10px] text-gray-400 mt-1 uppercase tracking-tight">Status Global OK</span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-5 align-top">
                                            <div className="flex items-center justify-end gap-1 group-hover:opacity-100 transition-opacity">
                                                {isAdmin && u.id !== me?.id ? (
                                                    <>
                                                        <ActionButton
                                                            icon={Edit3}
                                                            onClick={() => { setModalUser({ type: 'edit', user: u }); setFormData({ nombre: u.nombre, email: u.email }); }}
                                                            title="Editar Perfil"
                                                        />
                                                        <ActionButton
                                                            icon={Key}
                                                            onClick={() => { setModalUser({ type: 'reset', user: u }); setFormData({ password: '' }); }}
                                                            title="Reestablecer Contraseña"
                                                        />
                                                        <div className="w-[1px] h-6 bg-gray-100 mx-1"></div>
                                                        <ActionButton
                                                            icon={UserCheck}
                                                            onClick={() => { setModalUser({ type: 'access', user: u }); setAccesoData({ empresa_id: '', rol: 'vendedor' }); }}
                                                            title="Asignar a otra Empresa"
                                                            color="text-emerald-500 hover:text-emerald-700"
                                                            bg="hover:bg-emerald-50"
                                                        />
                                                        <ActionButton
                                                            icon={UserX}
                                                            onClick={() => handleRevocar(u.id)}
                                                            title="Baja de esta Empresa"
                                                            color="text-red-500 hover:text-red-700"
                                                            bg="hover:bg-red-50"
                                                        />
                                                    </>
                                                ) : (
                                                    <span className="text-[10px] font-black text-gray-200 uppercase">Sin Acciones</span>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>

            {/* Banner de Info */}
            < div className="bg-gradient-to-r from-gray-900 via-indigo-900 to-indigo-900 p-8 rounded-[2.5rem] text-white flex flex-col md:flex-row items-center justify-between gap-6 shadow-xl relative overflow-hidden" >
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-20 -mt-20 blur-3xl"></div>
                <div className="relative z-10">
                    <h3 className="text-xl font-bold mb-2">💡 Arquitectura de Roles Senior</h3>
                    <p className="text-indigo-100 text-sm max-w-xl leading-relaxed">
                        Los permisos son independientes por empresa. Un usuario puede ser **Administrador** en la casa central y **Vendedor** en una sucursal.
                        Revocar el acceso de un usuario **no elimina su cuenta global**, permitiéndole seguir trabajando en otras empresas a las que pertenece.
                    </p>
                </div>
                <div className="flex gap-4 shrink-0 relative z-10 w-full md:w-auto">
                    <div className="flex-1 bg-white/10 backdrop-blur-md rounded-2xl p-4 border border-white/5 text-center">
                        <span className="block text-2xl font-black">{users.length}</span>
                        <span className="text-[10px] uppercase font-bold tracking-widest text-indigo-300">Miembros</span>
                    </div>
                    <div className="flex-1 bg-white/10 backdrop-blur-md rounded-2xl p-4 border border-white/5 text-center">
                        <span className="block text-2xl font-black">{users.filter(u => u.rol === 'admin').length}</span>
                        <span className="text-[10px] uppercase font-bold tracking-widest text-indigo-300">Admins</span>
                    </div>
                </div>
            </div >

            {/* ── MODALES RE-DISEÑADOS ────────────────────────────────── */}

            {
                modalUser && (
                    <div className="fixed inset-0 z-[110] flex items-center justify-center p-4">
                        <div className="absolute inset-0 bg-black/60 backdrop-blur-sm animate-in fade-in duration-200" onClick={closeModals}></div>
                        <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden relative z-10 animate-in slide-in-from-bottom-8 duration-300">
                            {/* Modal Header */}
                            <div className="px-8 pt-8 pb-4 flex items-center justify-between">
                                <div>
                                    <h3 className="text-xl font-black text-gray-900">
                                        {modalUser.type === 'create' && 'Registrar Nuevo Miembro'}
                                        {modalUser.type === 'edit' && 'Editar Perfil'}
                                        {modalUser.type === 'reset' && 'Nueva Contraseña'}
                                        {modalUser.type === 'access' && 'Asignar Empresa'}
                                    </h3>
                                    <p className="text-xs text-gray-400 font-bold uppercase tracking-tight mt-1">
                                        {modalUser.user ? `Relacionado a: ${modalUser.user.nombre}` : 'Completa los datos del sistema'}
                                    </p>
                                </div>
                                <button onClick={closeModals} className="p-2 hover:bg-gray-100 rounded-xl transition text-gray-400">
                                    <X size={20} />
                                </button>
                            </div>

                            {/* Modal Body */}
                            <div className="px-8 pb-8">
                                <form className="space-y-4" onSubmit={
                                    modalUser.type === 'create' ? handleCreateUser :
                                        modalUser.type === 'edit' ? handleEditUser :
                                            modalUser.type === 'reset' ? handleResetPassword :
                                                handleDarAcceso
                                }>

                                    {/* Campos dinámicos según el tipo de modal */}
                                    {(modalUser.type === 'create' || modalUser.type === 'edit') && (
                                        <>
                                            <div>
                                                <label className="block text-xs font-black uppercase text-gray-400 tracking-wider mb-1.5 ml-1">Nombre Completo</label>
                                                <input required className={inputCls} placeholder="Ej: Juan Pérez" value={formData.nombre} onChange={e => setFormData(f => ({ ...f, nombre: e.target.value }))} />
                                            </div>
                                            <div>
                                                <label className="block text-xs font-black uppercase text-gray-400 tracking-wider mb-1.5 ml-1">Email Profesional</label>
                                                <input type="email" required className={inputCls} placeholder="ejemplo@correo.com" value={formData.email} onChange={e => setFormData(f => ({ ...f, email: e.target.value }))} />
                                            </div>
                                        </>
                                    )}

                                    {(modalUser.type === 'create' || modalUser.type === 'reset') && (
                                        <div>
                                            <label className="block text-xs font-black uppercase text-gray-400 tracking-wider mb-1.5 ml-1">Contraseña</label>
                                            <div className="relative">
                                                <input
                                                    type={showPassword ? 'text' : 'password'}
                                                    required
                                                    minLength={8}
                                                    className={`${inputCls} pr-12`}
                                                    placeholder="Mínimo 8 caracteres"
                                                    value={formData.password}
                                                    onChange={e => setFormData(f => ({ ...f, password: e.target.value }))}
                                                />
                                                <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-indigo-600 transition">
                                                    {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                                                </button>
                                            </div>
                                        </div>
                                    )}

                                    {modalUser.type === 'create' && (
                                        <div>
                                            <label className="block text-xs font-black uppercase text-gray-400 tracking-wider mb-1.5 ml-1">Rol Inicial</label>
                                            <select className={inputCls} value={formData.rol} onChange={e => setFormData(f => ({ ...f, rol: e.target.value }))}>
                                                {Object.entries(ROL_CONFIG).map(([v, c]) => (
                                                    <option key={v} value={v}>{c.label}</option>
                                                ))}
                                            </select>
                                        </div>
                                    )}

                                    {modalUser.type === 'access' && (
                                        <>
                                            <div>
                                                <label className="block text-xs font-black uppercase text-gray-400 tracking-wider mb-1.5 ml-1">Seleccionar Empresa</label>
                                                <div className="relative">
                                                    <select
                                                        required
                                                        className={`${inputCls} appearance-none pr-10`}
                                                        value={accesoData.empresa_id}
                                                        onChange={e => setAccesoData(a => ({ ...a, empresa_id: e.target.value }))}
                                                    >
                                                        <option value="">Elegir empresa de la lista...</option>
                                                        {empresasDisponibles.map(emp => (
                                                            <option key={emp.id} value={emp.id}>{emp.nombre}</option>
                                                        ))}
                                                    </select>
                                                    <ChevronDown size={18} className="absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400" />
                                                </div>
                                                <p className="text-[10px] text-indigo-500 font-bold mt-1.5 ml-1 uppercase letter tracking-tighter italic">Solo empresas activas en el sistema</p>
                                            </div>
                                            <div>
                                                <label className="block text-xs font-black uppercase text-gray-400 tracking-wider mb-1.5 ml-1">Rol en esta empresa</label>
                                                <select className={inputCls} value={accesoData.rol} onChange={e => setAccesoData(a => ({ ...a, rol: e.target.value }))}>
                                                    {Object.entries(ROL_CONFIG).map(([v, c]) => (
                                                        <option key={v} value={v}>{c.label}</option>
                                                    ))}
                                                </select>
                                            </div>
                                        </>
                                    )}

                                    {/* Modal Footer */}
                                    <div className="pt-6 flex gap-3">
                                        <button
                                            type="submit"
                                            disabled={submitting}
                                            className="flex-1 h-12 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-2xl transition-all shadow-lg shadow-indigo-200 active:scale-95 disabled:grayscale"
                                        >
                                            {submitting ? (
                                                <RefreshCw size={18} className="animate-spin" />
                                            ) : (
                                                <>
                                                    {modalUser.type === 'access' && <UserCheck size={18} />}
                                                    {modalUser.type === 'edit' && <Edit3 size={18} />}
                                                    {modalUser.type === 'reset' && <Key size={18} />}
                                                    {modalUser.type === 'create' && <Check size={18} />}
                                                    Guardar Cambios
                                                </>
                                            )}
                                        </button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    </div>
                )
            }

            {/* Confirmation Modal */}
            <ConfirmModal
                show={!!confirmAction}
                {...confirmAction}
                onCancel={() => setConfirmAction(null)}
            />

        </div >
    );
};

export default Users;
