import React from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { LayoutDashboard, Package, ArrowRightLeft, LogOut, FileText, Users as UsersIcon, Building2, Users as CustomersIcon, ShoppingCart } from 'lucide-react';
import { useAuth } from '../context/AuthContext';

const MainLayout = ({ onLogout }) => {
    const location = useLocation();
    const { user, logout, misEmpresas, switchEmpresa } = useAuth();

    const handleLogout = () => {
        logout();
        if (onLogout) onLogout();
    };

    const currentEmpresaId = user?.empresa_id;
    const currentEmpresa = misEmpresas.find(e => e.empresa_id === currentEmpresaId);


    const baseNavItems = [
        { name: 'Dashboard', path: '/', icon: <LayoutDashboard size={20} /> },
        { name: 'Productos', path: '/productos', icon: <Package size={20} /> },
        { name: 'Movimientos', path: '/movimientos', icon: <ArrowRightLeft size={20} /> },
        { name: 'Vender (POS)', path: '/facturacion', icon: <ShoppingCart size={20} /> },
        { name: 'Clientes', path: '/clientes', icon: <CustomersIcon size={20} /> },
        { name: 'Reportes', path: '/reportes', icon: <FileText size={20} /> }
    ];

    const navItems = user?.rol === 'admin'
        ? [...baseNavItems,
        { name: 'Usuarios', path: '/usuarios', icon: <UsersIcon size={20} /> },
        { name: 'Empresa', path: '/empresa', icon: <Building2 size={20} /> }
        ]
        : baseNavItems;

    return (
        <div className="flex h-screen bg-gray-50">
            {/* Sidebar */}
            <aside className="w-64 bg-white border-r border-gray-200 shadow-sm flex flex-col hidden md:flex">
                <div className="h-16 flex items-center px-6 border-b border-gray-200 justify-between">
                    <h1 className="text-xl font-bold text-indigo-600">Stock Pro</h1>
                </div>

                {/* Selector de Empresa — Solo si tiene múltiples */}
                {misEmpresas.length > 1 && (
                    <div className="px-4 py-4 border-b border-gray-100 bg-gray-50/50">
                        <label className="block text-[10px] font-black uppercase text-gray-400 tracking-widest mb-2 ml-1">
                            Empresa Activa
                        </label>
                        <div className="relative group">
                            <select
                                value={currentEmpresaId || ''}
                                onChange={(e) => switchEmpresa(Number(e.target.value))}
                                className="w-full appearance-none bg-white border border-gray-200 rounded-xl px-3 py-2 text-xs font-bold text-gray-700 outline-none focus:ring-2 focus:ring-indigo-500 transition-all cursor-pointer shadow-sm group-hover:border-indigo-300"
                            >
                                {misEmpresas.map(emp => (
                                    <option key={emp.id || emp.empresa_id} value={emp.empresa_id}>
                                        {emp.empresa_nombre}
                                    </option>
                                ))}
                            </select>
                            <Building2 size={14} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 pointer-events-none group-hover:text-indigo-500 transition-colors" />
                        </div>
                    </div>
                )}

                <div className="flex-1 overflow-y-auto py-4">
                    <nav className="space-y-1 px-3">
                        {navItems.map((item) => {
                            const isActive = location.pathname === item.path;
                            return (
                                <Link
                                    key={item.name}
                                    to={item.path}
                                    className={`flex items-center px-3 py-2.5 text-sm font-medium rounded-md transition-colors ${isActive
                                        ? 'bg-indigo-50 text-indigo-700'
                                        : 'text-gray-700 hover:bg-gray-100 hover:text-gray-900'
                                        }`}
                                >
                                    <span className={`mr-3 ${isActive ? 'text-indigo-700' : 'text-gray-400'}`}>
                                        {item.icon}
                                    </span>
                                    {item.name}
                                </Link>
                            );
                        })}
                    </nav>
                </div>

                <div className="p-4 border-t border-gray-200">
                    <div className="flex items-center mb-4">
                        <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-indigo-500 to-purple-600 flex items-center justify-center text-white font-bold shadow-md">
                            {user?.nombre?.[0]?.toUpperCase() || 'U'}
                        </div>
                        <div className="ml-3 truncate">
                            <p className="text-sm font-bold text-gray-800 truncate">{user?.nombre || user?.email}</p>
                            <p className="text-[10px] font-black uppercase tracking-tighter text-indigo-500">{user?.rol || 'Usuario'}</p>
                        </div>
                    </div>
                    <button
                        onClick={handleLogout}
                        className="w-full flex items-center justify-center px-4 py-2 text-sm font-bold text-red-600 bg-red-50 hover:bg-red-100 rounded-xl transition-all active:scale-95"
                    >
                        <LogOut size={16} className="mr-2" />
                        Cerrar Sesión
                    </button>
                </div>
            </aside>

            {/* Main content */}
            <main className="flex-1 flex flex-col overflow-hidden">
                {/* Mobile header could go here */}
                <div className="flex-1 overflow-y-auto p-6 md:p-8">
                    <Outlet />
                </div>
            </main>
        </div>
    );
};

export default MainLayout;
