import React, { useState, useEffect } from 'react';
import api from '../utils/axiosConfig';
import { useAuth } from '../context/AuthContext';
import {
    Package, AlertTriangle, DollarSign, ShoppingCart,
    TrendingUp, TrendingDown, ArrowUpRight, ArrowDownRight,
    FileText, RefreshCw, BarChart2, Zap
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

// ─── KPI Card ────────────────────────────────────────────────
const KpiCard = ({ icon: Icon, label, value, sub, color, gradient }) => (
    <div className={`relative overflow-hidden rounded-2xl p-6 text-white shadow-lg ${gradient}`}>
        <div className="absolute -right-4 -top-4 opacity-10">
            <Icon size={100} strokeWidth={1} />
        </div>
        <div className={`inline-flex items-center justify-center w-12 h-12 rounded-xl bg-white/20 mb-4`}>
            <Icon size={22} className="text-white" />
        </div>
        <p className="text-sm font-medium text-white/70 uppercase tracking-widest">{label}</p>
        <p className="text-3xl font-black mt-1 tracking-tight">{value}</p>
        {sub && <p className="text-xs text-white/60 mt-2">{sub}</p>}
    </div>
);

// ─── Section Header ──────────────────────────────────────────
const SectionHeader = ({ icon: Icon, title }) => (
    <div className="flex items-center gap-2 mb-4">
        <div className="bg-indigo-100 p-2 rounded-lg">
            <Icon size={18} className="text-indigo-600" />
        </div>
        <h2 className="text-base font-bold text-gray-800">{title}</h2>
    </div>
);

// ─── Main Dashboard ──────────────────────────────────────────
const Dashboard = () => {
    const { token } = useAuth();
    const [products, setProducts] = useState([]);
    const [recentActivity, setRecentActivity] = useState([]);
    const [recentFacturas, setRecentFacturas] = useState([]);
    const [topProducts, setTopProducts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [lastUpdated, setLastUpdated] = useState(null);

    const fetchAll = async () => {
        setLoading(true);
        try {
            const now = new Date();
            const monthStart = new Date(now.getFullYear(), now.getMonth(), 1).toISOString().slice(0, 10);
            const today = now.toISOString().slice(0, 10);

            const [prodRes, actRes, factRes, topRes] = await Promise.allSettled([
                api.get('/productos'),
                api.get('/movimientos/recientes'),
                api.get('/facturacion'),
                api.get(`/reportes/ventas-producto?fechaInicio=${monthStart}&fechaFin=${today}`),
            ]);

            if (prodRes.status === 'fulfilled') setProducts(prodRes.value.data);
            else console.error('Error cargando productos:', prodRes.reason?.message);

            if (actRes.status === 'fulfilled') setRecentActivity(actRes.value.data.slice(0, 6));
            if (factRes.status === 'fulfilled') setRecentFacturas(factRes.value.data.slice(0, 5));
            if (topRes.status === 'fulfilled') {
                setTopProducts(topRes.value.data.sort((a, b) => b.total_ventas - a.total_ventas).slice(0, 5));
            }
            setLastUpdated(new Date().toLocaleTimeString());
        } catch (e) {
            console.error('Dashboard fetch error', e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (token) fetchAll();
    }, [token]);

    // Computed KPIs
    const totalProducts = products.length;
    const lowStockItems = products.filter(p => p.stock <= 5 && p.stock >= 0);
    const criticalItems = products.filter(p => p.stock === 0);
    const totalValue = products.reduce((s, p) => s + (p.precio || 0) * (p.stock || 0), 0);
    const totalSales = recentFacturas.reduce((s, f) => s + Number(f.total || 0), 0);

    const BAR_COLORS = ['#6366f1', '#8b5cf6', '#a78bfa', '#c4b5fd', '#ddd6fe'];

    return (
        <div className="space-y-8">
            {/* Page Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-2xl font-black text-gray-900">Panel de Control</h1>
                    <p className="text-sm text-gray-400 mt-0.5">
                        {lastUpdated ? `Última actualización: ${lastUpdated}` : 'Cargando datos...'}
                    </p>
                </div>
                <button
                    onClick={fetchAll}
                    disabled={loading}
                    className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white text-sm font-bold rounded-xl hover:bg-indigo-700 transition disabled:opacity-60"
                >
                    <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                    Actualizar
                </button>
            </div>

            {/* KPI Grid */}
            <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-5">
                <KpiCard
                    icon={Package}
                    label="Total Productos"
                    value={totalProducts}
                    sub={`${criticalItems.length} sin stock`}
                    gradient="bg-gradient-to-br from-indigo-500 to-indigo-700"
                />
                <KpiCard
                    icon={AlertTriangle}
                    label="Stock Bajo (≤5)"
                    value={lowStockItems.length}
                    sub={lowStockItems.length > 0 ? `Requieren atención` : 'Todo en orden ✓'}
                    gradient={lowStockItems.length > 0 ? "bg-gradient-to-br from-amber-500 to-orange-600" : "bg-gradient-to-br from-green-500 to-emerald-600"}
                />
                <KpiCard
                    icon={DollarSign}
                    label="Valor del Inventario"
                    value={`$${totalValue.toLocaleString('es', { minimumFractionDigits: 2 })}`}
                    sub="Valor en bodega"
                    gradient="bg-gradient-to-br from-emerald-500 to-teal-600"
                />
                <KpiCard
                    icon={ShoppingCart}
                    label="Ventas (este mes)"
                    value={`$${totalSales.toLocaleString('es', { minimumFractionDigits: 2 })}`}
                    sub={`${recentFacturas.length} facturas emitidas`}
                    gradient="bg-gradient-to-br from-violet-500 to-purple-700"
                />
            </div>

            {/* Middle Row: Top Products Chart + Stock Alerts */}
            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">

                {/* Top Products Bar Chart */}
                <div className="lg:col-span-3 bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                    <SectionHeader icon={BarChart2} title="Top 5 Productos por Ventas (mes actual)" />
                    {topProducts.length > 0 ? (
                        <ResponsiveContainer width="100%" height={220}>
                            <BarChart data={topProducts} barCategoryGap="30%">
                                <XAxis
                                    dataKey="nombre"
                                    tick={{ fontSize: 11, fill: '#6b7280' }}
                                    axisLine={false}
                                    tickLine={false}
                                    interval={0}
                                    tickFormatter={v => v.length > 12 ? v.slice(0, 12) + '…' : v}
                                />
                                <YAxis hide />
                                <Tooltip
                                    formatter={(v) => [`$${Number(v).toFixed(2)}`, 'Ventas']}
                                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 24px rgba(0,0,0,0.1)' }}
                                />
                                <Bar dataKey="total_ventas" radius={[8, 8, 0, 0]}>
                                    {topProducts.map((_, i) => (
                                        <Cell key={i} fill={BAR_COLORS[i % BAR_COLORS.length]} />
                                    ))}
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    ) : (
                        <div className="h-[220px] flex flex-col items-center justify-center text-gray-300">
                            <BarChart2 size={48} strokeWidth={1} />
                            <p className="text-sm mt-2">Sin datos de ventas este mes</p>
                        </div>
                    )}
                </div>

                {/* Stock Alert Panel */}
                <div className="lg:col-span-2 bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                    <SectionHeader icon={AlertTriangle} title="Alertas de Stock Crítico" />
                    {lowStockItems.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-48 text-gray-300">
                            <Zap size={40} strokeWidth={1} className="text-green-400 mb-2" />
                            <p className="text-sm text-green-500 font-medium">¡Todos los productos con stock suficiente!</p>
                        </div>
                    ) : (
                        <div className="space-y-2 max-h-56 overflow-y-auto pr-1">
                            {lowStockItems.map(p => (
                                <div key={p.id} className={`flex items-center justify-between p-3 rounded-xl ${p.stock === 0 ? 'bg-red-50 border border-red-100' : 'bg-amber-50 border border-amber-100'}`}>
                                    <div className="min-w-0 mr-2">
                                        <p className="text-sm font-semibold text-gray-800 truncate">{p.nombre}</p>
                                        <p className="text-xs text-gray-400">{p.categoria || 'Sin categoría'}</p>
                                    </div>
                                    <span className={`flex-shrink-0 text-xs font-black px-2 py-1 rounded-full ${p.stock === 0 ? 'bg-red-500 text-white' : 'bg-amber-400 text-white'}`}>
                                        {p.stock === 0 ? 'AGOTADO' : `${p.stock} uds`}
                                    </span>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            </div>

            {/* Bottom Row: Recent Invoices + Activity Feed */}
            <div className="grid grid-cols-1 lg:grid-cols-5 gap-6">

                {/* Recent Invoices */}
                <div className="lg:col-span-3 bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                    <SectionHeader icon={FileText} title="Últimas Facturas Emitidas" />
                    {recentFacturas.length === 0 ? (
                        <p className="text-sm text-gray-400 py-8 text-center">No hay facturas registradas.</p>
                    ) : (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm">
                                <thead>
                                    <tr className="border-b border-gray-100 text-[10px] font-bold text-gray-400 uppercase">
                                        <th className="pb-2 text-left">Nro.</th>
                                        <th className="pb-2 text-left">Cliente</th>
                                        <th className="pb-2 text-right">Total</th>
                                        <th className="pb-2 text-center">Estado</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-50">
                                    {recentFacturas.map(f => (
                                        <tr key={f.id} className="hover:bg-gray-50 transition">
                                            <td className="py-3 font-mono text-xs font-bold text-indigo-600">{f.nro_factura}</td>
                                            <td className="py-3 text-gray-700 font-medium max-w-[120px] truncate">{f.cliente_nombre}</td>
                                            <td className="py-3 text-right font-bold text-gray-900">${Number(f.total).toFixed(2)}</td>
                                            <td className="py-3 text-center">
                                                <span className="px-2 py-0.5 rounded-full text-[10px] font-bold bg-green-100 text-green-700 uppercase">{f.estado}</span>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </div>

                {/* Activity Feed */}
                <div className="lg:col-span-2 bg-white rounded-2xl border border-gray-100 shadow-sm p-6">
                    <SectionHeader icon={TrendingUp} title="Movimientos Recientes" />
                    {recentActivity.length === 0 ? (
                        <p className="text-sm text-gray-400 py-8 text-center">Sin movimientos recientes.</p>
                    ) : (
                        <ul className="space-y-3">
                            {recentActivity.map((mov, i) => {
                                const isEntrada = mov.tipo?.toLowerCase() === 'entrada';
                                return (
                                    <li key={mov.id || i} className="flex items-start gap-3">
                                        <span className={`mt-0.5 flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${isEntrada ? 'bg-green-100' : 'bg-red-100'}`}>
                                            {isEntrada
                                                ? <ArrowDownRight size={16} className="text-green-600" />
                                                : <ArrowUpRight size={16} className="text-red-600" />
                                            }
                                        </span>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm text-gray-700">
                                                <span className="font-semibold">{isEntrada ? 'Ingreso' : 'Salida'}</span>
                                                {' · '}<span className="text-gray-500 text-xs truncate">{mov.producto}</span>
                                            </p>
                                            <p className="text-xs text-gray-400">
                                                {mov.fecha ? new Date(mov.fecha.endsWith('Z') ? mov.fecha.slice(0, -1) : mov.fecha).toLocaleDateString() : ''}
                                            </p>
                                        </div>
                                        <span className={`flex-shrink-0 text-sm font-black ${isEntrada ? 'text-green-600' : 'text-red-500'}`}>
                                            {isEntrada ? '+' : '-'}{mov.cantidad}
                                        </span>
                                    </li>
                                );
                            })}
                        </ul>
                    )}
                </div>
            </div>
        </div>
    );
};

export default Dashboard;
