import React, { useState, useEffect } from 'react';
import api from '../utils/axiosConfig';
import { useAuth } from '../context/AuthContext';
import { Users as CustomersIcon, Plus, Search, Edit2, Trash2, Mail, Phone, MapPin } from 'lucide-react';
import { toast } from 'react-hot-toast';

const Clientes = () => {
    const { token } = useAuth();
    const [clientes, setClientes] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showModal, setShowModal] = useState(false);
    const [editingCliente, setEditingCliente] = useState(null);
    const [formData, setFormData] = useState({
        nombre: '',
        documento_identidad: '',
        email: '',
        telefono: '',
        direccion: ''
    });

    useEffect(() => {
        if (token) {
            fetchClientes();
        }
    }, [token]);

    const fetchClientes = async () => {
        setLoading(true);
        try {
            const res = await api.get('/clientes');
            setClientes(res.data);
        } catch (err) {
            toast.error('Error al cargar la cartera de clientes');
        } finally {
            setLoading(false);
        }
    };

    const handleOpenModal = (cliente = null) => {
        if (cliente) {
            setEditingCliente(cliente);
            setFormData({
                nombre: cliente.nombre,
                documento_identidad: cliente.documento_identidad,
                email: cliente.email || '',
                telefono: cliente.telefono || '',
                direccion: cliente.direccion || ''
            });
        } else {
            setEditingCliente(null);
            setFormData({ nombre: '', documento_identidad: '', email: '', telefono: '', direccion: '' });
        }
        setShowModal(true);
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingCliente) {
                await api.put(`/clientes/${editingCliente.id}`, formData);
                toast.success('Cliente actualizado exitosamente');
            } else {
                await api.post('/clientes', formData);
                toast.success('Cliente registrado exitosamente');
            }
            setShowModal(false);
            fetchClientes();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al guardar cliente');
        }
    };

    const handleDelete = async (id) => {
        if (!window.confirm('¿Está seguro de eliminar este cliente?')) return;
        try {
            await api.delete(`/clientes/${id}`);
            toast.success('Cliente eliminado');
            fetchClientes();
        } catch (err) {
            toast.error(err.response?.data?.error || 'Error al eliminar cliente');
        }
    };

    const filteredClientes = clientes.filter(c => {
        const term = searchTerm.toLowerCase();
        return (c.nombre && String(c.nombre).toLowerCase().includes(term)) ||
            (c.documento_identidad && String(c.documento_identidad).includes(searchTerm));
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h1 className="text-2xl font-bold text-gray-900 flex items-center">
                    <CustomersIcon className="mr-3 text-indigo-600" size={28} />
                    Directorio de Clientes
                </h1>
                <button
                    onClick={() => handleOpenModal()}
                    className="flex items-center px-4 py-2 bg-indigo-600 text-white text-sm font-medium rounded-md hover:bg-indigo-700 transition"
                >
                    <Plus size={16} className="mr-2" />
                    Nuevo Cliente
                </button>
            </div>

            {/* Filtros */}
            <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-200">
                <div className="relative max-w-md">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        placeholder="Buscar por nombre o documento..."
                        className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-md leading-5 bg-white placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm"
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
            </div>

            {/* Listado de Clientes Grid (Cards instead of Table for better UX density) */}
            {loading ? (
                <div className="flex justify-center py-20">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-indigo-600"></div>
                </div>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                    {filteredClientes.map(cliente => (
                        <div key={cliente.id} className="bg-white rounded-lg border border-gray-200 shadow-sm hover:shadow-md transition-shadow duration-200 p-5">
                            <div className="flex justify-between items-start mb-4">
                                <div>
                                    <h3 className="text-lg font-semibold text-gray-900">{cliente.nombre}</h3>
                                    <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-gray-100 text-gray-800 mt-1">
                                        ID: {cliente.documento_identidad}
                                    </span>
                                </div>
                                <div className="flex space-x-1">
                                    <button onClick={() => handleOpenModal(cliente)} className="p-1.5 text-gray-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-md transition" title="Editar">
                                        <Edit2 size={16} />
                                    </button>
                                    <button onClick={() => handleDelete(cliente.id)} className="p-1.5 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-md transition" title="Eliminar">
                                        <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>

                            <div className="space-y-2 text-sm text-gray-600">
                                {cliente.email && (
                                    <div className="flex items-center">
                                        <Mail size={14} className="mr-2 text-gray-400" />
                                        <a href={`mailto:${cliente.email}`} className="hover:text-indigo-600">{cliente.email}</a>
                                    </div>
                                )}
                                {cliente.telefono && (
                                    <div className="flex items-center">
                                        <Phone size={14} className="mr-2 text-gray-400" />
                                        <span>{cliente.telefono}</span>
                                    </div>
                                )}
                                {cliente.direccion && (
                                    <div className="flex items-start">
                                        <MapPin size={14} className="mr-2 text-gray-400 mt-0.5" />
                                        <span className="line-clamp-2">{cliente.direccion}</span>
                                    </div>
                                )}
                            </div>
                        </div>
                    ))}
                    {filteredClientes.length === 0 && (
                        <div className="col-span-full py-12 text-center text-gray-500">
                            No se encontraron clientes con esos parámetros.
                        </div>
                    )}
                </div>
            )}

            {/* Modal Crear/Editar Cliente */}
            {showModal && (
                <div className="fixed inset-0 z-50 flex items-center justify-center overflow-x-hidden overflow-y-auto outline-none focus:outline-none bg-black bg-opacity-50">
                    <div className="relative w-full max-w-md mx-auto my-6">
                        <div className="relative flex flex-col w-full bg-white border-0 rounded-lg shadow-lg outline-none focus:outline-none">
                            <div className="flex items-start justify-between p-5 border-b border-solid border-gray-200 rounded-t">
                                <h3 className="text-xl font-semibold">{editingCliente ? 'Editar Cliente' : 'Nuevo Cliente'}</h3>
                                <button className="p-1 ml-auto bg-transparent border-0 text-gray-400 float-right text-3xl leading-none font-semibold outline-none focus:outline-none hover:text-gray-600" onClick={() => setShowModal(false)}>
                                    <span className="block w-6 h-6 text-2xl -mt-1">×</span>
                                </button>
                            </div>
                            <div className="relative p-6 flex-auto">
                                <form onSubmit={handleSubmit} className="space-y-4">
                                    <div className="grid grid-cols-1 gap-4">
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700">Nombre Completo *</label>
                                            <input type="text" required className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm" value={formData.nombre} onChange={(e) => setFormData({ ...formData, nombre: e.target.value })} />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700">NIT / DNI *</label>
                                            <input type="text" required className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm" value={formData.documento_identidad} onChange={(e) => setFormData({ ...formData, documento_identidad: e.target.value })} />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700">Teléfono</label>
                                            <input type="text" className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm" value={formData.telefono} onChange={(e) => setFormData({ ...formData, telefono: e.target.value })} />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700">Email</label>
                                            <input type="email" className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm" value={formData.email} onChange={(e) => setFormData({ ...formData, email: e.target.value })} />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-medium text-gray-700">Dirección Física</label>
                                            <textarea className="mt-1 block w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm" rows="2" value={formData.direccion} onChange={(e) => setFormData({ ...formData, direccion: e.target.value })}></textarea>
                                        </div>
                                    </div>
                                    <div className="pt-4 flex items-center justify-end border-t border-solid border-gray-200">
                                        <button type="button" className="text-gray-500 background-transparent font-bold px-6 py-2 text-sm outline-none focus:outline-none mr-1 mb-1 hover:text-gray-700 transition" onClick={() => setShowModal(false)}>Cancelar</button>
                                        <button type="submit" className="bg-indigo-600 text-white font-bold text-sm px-6 py-3 rounded shadow hover:bg-indigo-700 transition">Guardar Cliente</button>
                                    </div>
                                </form>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default Clientes;
