import React, { useState, useEffect, useMemo } from 'react';
import api from '../utils/axiosConfig';
import { useAuth } from '../context/AuthContext';
import { ShoppingCart, Plus, Trash2, Search, FileText, CheckCircle, Package, User, CreditCard, ArrowRight, RefreshCw, X, Minus } from 'lucide-react';
import { toast } from 'react-hot-toast';

// ── Componentes Atómicos Senior ──────────────────────────────────
const StatDetail = ({ label, value, color = "text-gray-600" }) => (
    <div className="flex justify-between items-center py-2">
        <span className="text-sm text-gray-400 font-medium">{label}</span>
        <span className={`text-sm font-bold ${color}`}>{value}</span>
    </div>
);

const POSButton = ({ onClick, disabled, children, variant = "primary", className = "" }) => {
    const variants = {
        primary: "bg-indigo-600 hover:bg-indigo-700 text-white shadow-indigo-100",
        success: "bg-emerald-600 hover:bg-emerald-700 text-white shadow-emerald-100",
        danger: "bg-rose-50 hover:bg-rose-100 text-rose-600",
        ghost: "bg-gray-50 hover:bg-gray-100 text-gray-600"
    };
    return (
        <button
            disabled={disabled}
            onClick={onClick}
            className={`px-4 py-2 rounded-xl text-sm font-bold transition-all active:scale-95 disabled:opacity-50 disabled:pointer-events-none shadow-sm flex items-center justify-center gap-2 ${variants[variant]} ${className}`}
        >
            {children}
        </button>
    );
};

const Facturacion = () => {
    const { token } = useAuth();

    // Maestros
    const [clientes, setClientes] = useState([]);
    const [productos, setProductos] = useState([]);
    const [empresa, setEmpresa] = useState({});

    // Estado del POS
    const [clienteId, setClienteId] = useState('');
    const [carrito, setCarrito] = useState([]);

    // UI State
    const [loading, setLoading] = useState(false);
    const [facturaAnterior, setFacturaAnterior] = useState(null);
    const [historicoFacturas, setHistoricoFacturas] = useState([]);

    // Filtros, Búsqueda y Cobro
    const [searchTerm, setSearchTerm] = useState('');
    const [pagoCon, setPagoCon] = useState('');
    const [vuelto, setVuelto] = useState(0);

    // Auditoría panel state
    const [auditSearch, setAuditSearch] = useState('');
    const [auditPage, setAuditPage] = useState(1);
    const AUDIT_PER_PAGE = 10;

    useEffect(() => {
        if (token) {
            cargarDatosMaestros();
        }
    }, [token]);

    const cargarDatosMaestros = async () => {
        try {
            const [resClientes, resProductos, resEmpresa] = await Promise.all([
                api.get('/clientes'),
                api.get('/productos'),
                api.get('/empresa')
            ]);

            const facturasRes = await api.get('/facturacion');

            setClientes(resClientes.data);
            setProductos(resProductos.data.filter(p => p.stock > 0));
            setEmpresa(resEmpresa.data);
            setHistoricoFacturas(facturasRes.data);
        } catch (err) {
            toast.error('Error al cargar datos del sistema');
        }
    };

    const eliminarDelCarrito = (producto_id) => {
        setCarrito(carrito.filter(item => item.producto_id !== producto_id));
    };

    // Cálculos Derivados
    const totalFactura = useMemo(() => carrito.reduce((sum, item) => sum + item.subtotal, 0), [carrito]);

    useEffect(() => {
        const pago = pagoCon === '' ? totalFactura : (parseFloat(pagoCon) || 0);
        if (pago >= totalFactura && totalFactura > 0) {
            setVuelto(pago - totalFactura);
        } else {
            setVuelto(0);
        }
    }, [pagoCon, totalFactura]);

    const productosFiltrados = useMemo(() => {
        if (!searchTerm) return [];
        const lowerSearch = searchTerm.toLowerCase();
        return productos.filter(p =>
            (p.nombre && String(p.nombre).toLowerCase().includes(lowerSearch)) ||
            (p.sku && String(p.sku).toLowerCase().includes(lowerSearch)) ||
            (p.descripcion && String(p.descripcion).toLowerCase().includes(lowerSearch))
        ).slice(0, 5);
    }, [productos, searchTerm]);

    const handlePrint = () => {
        window.print();
    };

    const handleAddFast = (prod) => {
        if (!clienteId) {
            toast.error('Debe seleccionar un cliente primero');
            return;
        }

        const enCarrito = carrito.find(item => item.producto_id === prod.id);
        const currentQty = enCarrito ? enCarrito.cantidad : 0;

        if (currentQty + 1 > prod.stock) {
            toast.error('Stock insuficiente');
            return;
        }

        if (enCarrito) {
            setCarrito(carrito.map(item =>
                item.producto_id === prod.id
                    ? { ...item, cantidad: item.cantidad + 1, subtotal: item.precio_unitario * (item.cantidad + 1) }
                    : item
            ));
        } else {
            setCarrito([...carrito, {
                producto_id: prod.id,
                nombre: prod.nombre,
                cantidad: 1,
                precio_unitario: prod.precio,
                subtotal: prod.precio
            }]);
        }
        setSearchTerm('');
        toast.success(`Agregado: ${prod.nombre}`);
    };

    const updateQty = (id, delta) => {
        setCarrito(prev => prev.map(item => {
            if (item.producto_id === id) {
                const newQty = Math.max(1, item.cantidad + delta);
                // Validar stock original
                const originalProd = productos.find(p => p.id === id);
                if (delta > 0 && newQty > originalProd.stock) {
                    toast.error('Límite de stock alcanzado');
                    return item;
                }
                return { ...item, cantidad: newQty, subtotal: item.precio_unitario * newQty };
            }
            return item;
        }));
    };

    const facturar = async () => {
        if (!clienteId) {
            toast.error('Debe seleccionar un cliente antes de completar la venta');
            return;
        }
        if (carrito.length === 0) {
            toast.error('El carrito está vacío');
            return;
        }

        const pago = pagoCon === '' ? totalFactura : (parseFloat(pagoCon) || 0);
        if (pago < totalFactura) {
            toast.error(`Ingreso insuficiente. Faltan $${(totalFactura - pago).toFixed(2)}`);
            return;
        }

        setLoading(true);
        try {
            const payload = {
                cliente_id: parseInt(clienteId),
                total: parseFloat(totalFactura.toFixed(2)),
                detalles: carrito
            };

            const res = await api.post('/facturacion', payload);
            // El servicio retorna la factura completa directamente (incluye nro_factura, detalles, etc.)
            const facturaCompleta = res.data;
            toast.success('¡Venta emitida y stock actualizado!');

            // Normalizar la fecha para evitar desfase de timezone
            if (facturaCompleta && facturaCompleta.fecha_emision) {
                const fe = facturaCompleta.fecha_emision;
                facturaCompleta.fecha_emision = fe.endsWith('Z') ? fe.slice(0, -1) : fe;
            }

            // Asegurar que los campos de empresa estén presentes (el GET interior del servicio puede omitirlos)
            if (facturaCompleta) {
                facturaCompleta.empresa_nombre_snapshot = facturaCompleta.empresa_nombre_snapshot || empresa.nombre;
                facturaCompleta.empresa_nit_snapshot = facturaCompleta.empresa_nit_snapshot || empresa.documento_identidad;
                facturaCompleta.empresa_direccion_snapshot = facturaCompleta.empresa_direccion_snapshot || empresa.direccion;
                facturaCompleta.empresa_telefono_snapshot = facturaCompleta.empresa_telefono_snapshot || empresa.telefono;
                // Si los detalles vienen vacíos, usar carrito como fallback
                if (!facturaCompleta.detalles || facturaCompleta.detalles.length === 0) {
                    facturaCompleta.detalles = carrito.map(item => ({
                        producto_nombre: item.nombre,
                        cantidad: item.cantidad,
                        precio_unitario: item.precio_unitario,
                        subtotal: item.subtotal
                    }));
                }
                setFacturaAnterior(facturaCompleta);
            }

            // Limpiar estados
            setCarrito([]);
            setClienteId('');
            setPagoCon('');
            setVuelto(0);
            setAuditPage(1);

            // Recarga maestros para actualizar historial y stock
            cargarDatosMaestros();

        } catch (err) {
            const errorMsg = err.response?.data?.error || err.message || 'Error en el servidor';
            toast.error(`Fallo en facturación: ${errorMsg}`);
        } finally {
            setLoading(false);
        }
    };

    const renderInvoiceSummary = () => {
        if (!facturaAnterior) return null;

        const empresaNombre = facturaAnterior.empresa_nombre_snapshot || empresa.nombre;
        const empresaNIT = facturaAnterior.empresa_nit_snapshot || empresa.documento_identidad;
        const empresaTel = facturaAnterior.empresa_telefono_snapshot || empresa.telefono;
        const empresaDir = facturaAnterior.empresa_direccion_snapshot || empresa.direccion;

        return (
            // Modal overlay a pantalla completa
            <div className="fixed inset-0 z-50 flex items-start justify-center bg-black/60 overflow-y-auto py-8 px-4">
                <style dangerouslySetInnerHTML={{
                    __html: `
                    @media print {
                        body > *:not(.invoice-print-root) { display: none !important; }
                        .invoice-print-root { 
                            position: fixed; inset: 0;
                            width: 100%; 
                            background: white;
                            padding: 40px;
                            z-index: 9999;
                        }
                        .no-print { display: none !important; }
                    }
                `}} />

                <div className="invoice-print-root bg-white rounded-2xl shadow-2xl w-full max-w-3xl">
                    {/* Barra de acciones (solo pantalla, no impresion) */}
                    <div className="no-print flex justify-between items-center px-8 pt-6 pb-4 border-b border-gray-100">
                        <div className="flex items-center gap-2 text-green-600">
                            <CheckCircle size={24} />
                            <span className="font-bold text-lg">¡Factura Emitida Exitosamente!</span>
                        </div>
                        <div className="flex gap-3">
                            <button
                                onClick={handlePrint}
                                className="flex items-center px-4 py-2 bg-indigo-600 text-white text-sm font-bold rounded-lg hover:bg-indigo-700 transition"
                            >
                                <FileText size={16} className="mr-2" /> Imprimir
                            </button>
                            <button
                                onClick={() => setFacturaAnterior(null)}
                                className="flex items-center px-4 py-2 bg-gray-100 text-gray-600 text-sm font-bold rounded-lg hover:bg-gray-200 transition"
                            >
                                ✕ Cerrar
                            </button>
                        </div>
                    </div>

                    {/* Contenido de la Factura */}
                    <div className="p-8">
                        {/* Encabezado empresa */}
                        <div className="flex justify-between items-start pb-6 border-b-2 border-gray-200 mb-6">
                            <div>
                                <h2 className="text-2xl font-black text-indigo-900 uppercase tracking-tight">{empresaNombre}</h2>
                                <p className="text-sm text-gray-500 mt-1">{empresaDir || 'Dirección no registrada'}</p>
                                <p className="text-sm text-gray-500">NIT/ID: <span className="font-medium">{empresaNIT}</span></p>
                                <p className="text-sm text-gray-500">Tel: <span className="font-medium">{empresaTel || 'N/A'}</span></p>
                            </div>
                            <div className="text-right bg-indigo-50 px-5 py-3 rounded-xl">
                                <p className="text-xs font-bold text-indigo-400 uppercase tracking-widest mb-1">Número de Factura</p>
                                <p className="text-xl font-mono font-black text-indigo-700">{facturaAnterior.nro_factura}</p>
                                <p className="text-xs text-gray-400 mt-1">{new Date(facturaAnterior.fecha_emision).toLocaleString()}</p>
                            </div>
                        </div>

                        {/* Cliente y Vendedor */}
                        <div className="grid grid-cols-2 gap-4 mb-8">
                            <div className="bg-gray-50 rounded-xl p-4 border border-gray-100">
                                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Cliente</p>
                                <p className="text-base font-bold text-gray-800">{facturaAnterior.cliente_nombre}</p>
                                <p className="text-sm text-gray-500">ID/DOC: {facturaAnterior.cliente_doc}</p>
                            </div>
                            <div className="bg-gray-50 rounded-xl p-4 border border-gray-100 text-right">
                                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">Vendedor</p>
                                <p className="text-base font-medium text-gray-700">{facturaAnterior.vendedor_nombre}</p>
                            </div>
                        </div>

                        {/* Tabla de productos */}
                        <table className="w-full mb-8 border-collapse">
                            <thead>
                                <tr className="border-b-2 border-gray-200 bg-gray-50">
                                    <th className="py-3 px-3 text-left text-xs font-bold text-gray-500 uppercase">Descripción</th>
                                    <th className="py-3 px-3 text-center text-xs font-bold text-gray-500 uppercase">Cantidad</th>
                                    <th className="py-3 px-3 text-right text-xs font-bold text-gray-500 uppercase">Precio Unit.</th>
                                    <th className="py-3 px-3 text-right text-xs font-bold text-gray-500 uppercase">Subtotal</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100">
                                {facturaAnterior.detalles?.map((d, idx) => (
                                    <tr key={idx}>
                                        <td className="py-4 px-3 font-medium text-gray-800">{d.producto_nombre || d.nombre}</td>
                                        <td className="py-4 px-3 text-center text-gray-600 font-mono">×{d.cantidad}</td>
                                        <td className="py-4 px-3 text-right text-gray-600">${Number(d.precio_unitario).toFixed(2)}</td>
                                        <td className="py-4 px-3 text-right font-bold text-gray-900">${Number(d.subtotal).toFixed(2)}</td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>

                        {/* Totales */}
                        <div className="flex justify-end">
                            <div className="w-72 space-y-2">
                                <div className="flex justify-between text-sm text-gray-500">
                                    <span>Subtotal gravado</span>
                                    <span>${Number(facturaAnterior.total).toFixed(2)}</span>
                                </div>
                                <div className="flex justify-between text-sm text-gray-500">
                                    <span>Impuestos (0%)</span>
                                    <span>$0.00</span>
                                </div>
                                <div className="border-t-2 border-indigo-100 pt-3 flex justify-between items-center">
                                    <span className="font-black text-indigo-900 uppercase">TOTAL</span>
                                    <span className="text-3xl font-black text-indigo-600">${Number(facturaAnterior.total).toFixed(2)}</span>
                                </div>
                            </div>
                        </div>

                        {/* Footer */}
                        <div className="mt-10 pt-6 border-t border-gray-100 text-center">
                            <p className="text-[10px] font-bold text-gray-300 uppercase tracking-widest">DOCUMENTO NO VÁLIDO COMO FACTURA FISCAL</p>
                            <p className="text-sm text-indigo-400 mt-2 font-semibold">¡Gracias por preferir a {empresaNombre}!</p>
                            <p className="text-[9px] text-gray-200 mt-3">Sistema de Inventario v2.0 · Audit ID: {facturaAnterior.id}</p>
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div className="max-w-[1600px] mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Header POS */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex items-center gap-4 text-indigo-600">
                    <div className="w-14 h-14 bg-indigo-50 rounded-3xl flex items-center justify-center text-indigo-600 shadow-sm border border-indigo-100">
                        <ShoppingCart size={28} />
                    </div>
                    <div>
                        <h1 className="text-2xl font-black text-gray-900 tracking-tight">Punto de Venta</h1>
                        <p className="text-sm text-gray-500 font-medium">Multi-Tenant Billing Center v2</p>
                    </div>
                </div>

                <div className="flex items-center gap-3">
                    <POSButton variant="ghost" onClick={cargarDatosMaestros}>
                        <RefreshCw size={16} className={loading ? 'animate-spin' : ''} />
                        Sincronizar
                    </POSButton>
                    <div className="h-10 w-[1px] bg-gray-200 mx-2 hidden md:block" />
                    <div className="text-right">
                        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest leading-none">Caja Abierta</p>
                        <p className="text-sm font-black text-indigo-600 font-mono mt-1 uppercase">{empresa.nombre}</p>
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 xl:grid-cols-12 gap-8 items-start">

                {/* 🛒 Column 1: Selector y Carrito (Lado Izquierdo) */}
                <div className="xl:col-span-8 space-y-6">

                    {/* Buscador de Productos y Cliente */}
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm transition-all hover:shadow-md">
                            <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest mb-3">
                                <User size={14} className="text-indigo-400" /> 1. Cliente Titular
                            </label>
                            <select
                                className="w-full bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 rounded-2xl px-4 py-3 text-sm font-bold text-gray-700 transition-all outline-none"
                                value={clienteId}
                                onChange={(e) => setClienteId(e.target.value)}
                            >
                                <option value="">Seleccione un cliente...</option>
                                {clientes.map(c => (
                                    <option key={c.id} value={c.id}>{c.nombre} ({c.documento_identidad})</option>
                                ))}
                            </select>
                        </div>

                        <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm relative transition-all hover:shadow-md">
                            <label className="flex items-center gap-2 text-xs font-black text-gray-400 uppercase tracking-widest mb-3">
                                <Package size={14} className="text-indigo-400" /> 2. Búsqueda de Productos
                            </label>
                            <div className="relative">
                                <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                <input
                                    type="text"
                                    placeholder="Nombre o código SKU..."
                                    className="w-full bg-gray-50 border-transparent focus:bg-white focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 rounded-2xl pl-12 pr-4 py-3 text-sm font-bold text-gray-700 transition-all outline-none"
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                />
                            </div>

                            {/* Resultados de búsqueda flotantes */}
                            {productosFiltrados.length > 0 && (
                                <div className="absolute left-6 right-6 top-[calc(100%+8px)] bg-white rounded-2xl shadow-2xl border border-gray-100 z-10 overflow-hidden divide-y divide-gray-50 animate-in fade-in slide-in-from-top-2 duration-200">
                                    {productosFiltrados.map(p => (
                                        <div
                                            key={p.id}
                                            onClick={() => handleAddFast(p)}
                                            className="p-4 hover:bg-indigo-50 cursor-pointer flex justify-between items-center group transition-all"
                                        >
                                            <div>
                                                <p className="text-sm font-black text-gray-800">{p.nombre}</p>
                                                <p className="text-[10px] text-gray-400 font-bold uppercase tracking-tight">Stock: {p.stock} units</p>
                                            </div>
                                            <div className="text-right">
                                                <p className="text-sm font-black text-indigo-600">${p.precio.toFixed(2)}</p>
                                                <p className="text-[10px] text-indigo-300 font-bold group-hover:text-indigo-500">Haz clic para agregar +</p>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>

                    {/* Detalle del Carrito */}
                    <div className="bg-white rounded-[32px] border border-gray-100 shadow-sm overflow-hidden flex flex-col min-h-[450px]">
                        <div className="px-6 py-5 bg-gray-50/50 border-b border-gray-100 flex justify-between items-center">
                            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                                <ShoppingCart size={16} /> Detalle de la Operación
                            </h3>
                            <span className="text-xs font-bold text-indigo-500 bg-indigo-50 px-3 py-1 rounded-full border border-indigo-100">
                                {carrito.length} Renglones
                            </span>
                        </div>

                        <div className="flex-1 overflow-x-auto">
                            <table className="w-full text-left">
                                <thead>
                                    <tr className="bg-gray-50/20 border-b border-gray-100">
                                        <th className="px-6 py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">Producto</th>
                                        <th className="px-6 py-4 text-center text-[10px] font-black text-gray-400 uppercase tracking-widest">Cantidad</th>
                                        <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Precio Unit.</th>
                                        <th className="px-6 py-4 text-right text-[10px] font-black text-gray-400 uppercase tracking-widest">Subtotal</th>
                                        <th className="px-6 py-4"></th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-50">
                                    {carrito.map(item => (
                                        <tr key={item.producto_id} className="hover:bg-indigo-50/20 transition-all group">
                                            <td className="px-6 py-5">
                                                <div className="flex flex-col">
                                                    <span className="text-sm font-black text-gray-800 group-hover:text-indigo-700 transition-colors uppercase tracking-tight">{item.nombre}</span>
                                                    <span className="text-[10px] text-gray-400 font-bold">Ref: #PROD-{item.producto_id}</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-5">
                                                <div className="flex items-center justify-center gap-3 bg-gray-100 p-1.5 rounded-2xl w-max mx-auto shadow-inner">
                                                    <button onClick={() => updateQty(item.producto_id, -1)} className="w-8 h-8 flex items-center justify-center bg-white rounded-xl text-gray-400 hover:text-rose-600 hover:shadow-sm transition-all shadow-indigo-100/10">
                                                        <Minus size={14} />
                                                    </button>
                                                    <span className="w-8 text-center text-sm font-black text-indigo-700 font-mono">{item.cantidad}</span>
                                                    <button onClick={() => updateQty(item.producto_id, 1)} className="w-8 h-8 flex items-center justify-center bg-white rounded-xl text-gray-400 hover:text-emerald-600 hover:shadow-sm transition-all shadow-indigo-100/10">
                                                        <Plus size={14} />
                                                    </button>
                                                </div>
                                            </td>
                                            <td className="px-6 py-5 text-right">
                                                <span className="text-sm font-bold text-gray-500">${item.precio_unitario.toFixed(2)}</span>
                                            </td>
                                            <td className="px-6 py-5 text-right whitespace-nowrap">
                                                <span className="text-base font-black text-gray-900 font-mono tracking-tighter">${item.subtotal.toFixed(2)}</span>
                                            </td>
                                            <td className="px-6 py-5 text-right">
                                                <button
                                                    onClick={() => eliminarDelCarrito(item.producto_id)}
                                                    className="w-10 h-10 flex items-center justify-center text-gray-300 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all"
                                                >
                                                    <Trash2 size={18} />
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                    {carrito.length === 0 && (
                                        <tr>
                                            <td colSpan="5" className="py-24 text-center">
                                                <div className="flex flex-col items-center gap-3 opacity-20">
                                                    <ShoppingCart size={64} className="text-gray-400" />
                                                    <p className="text-xl font-black text-gray-500 tracking-tighter">Buscá productos para empezar</p>
                                                </div>
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

                {/* 💳 Column 2: Resumen y Cobro (Lado Derecho) */}
                <div className="xl:col-span-4 space-y-6 lg:sticky lg:top-8">

                    <div className="bg-white rounded-[32px] p-8 border border-gray-100 shadow-xl relative overflow-hidden group">
                        <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/5 -mr-16 -mt-16 rounded-full blur-3xl group-hover:bg-indigo-500/10 transition-colors"></div>

                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-8 border-b border-gray-50 pb-4">
                            Resumen de Venta
                        </h3>

                        <div className="space-y-4 mb-8">
                            <StatDetail label="Subtotal Neto" value={`$${totalFactura.toFixed(2)}`} />
                            <StatDetail label="Impuestos (IVA 0%)" value="$0.00" />
                            <StatDetail label="Descuentos Aplicados" value="-$0.00" color="text-emerald-500" />

                            <div className="pt-6 mt-6 border-t border-gray-100 flex justify-between items-end">
                                <div>
                                    <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Total a Cobrar</p>
                                    <p className="text-5xl font-black text-indigo-600 font-mono tracking-tighter leading-none">${totalFactura.toFixed(2)}</p>
                                </div>
                            </div>
                        </div>

                        {/* Panel de Cobro */}
                        <div className="space-y-4 bg-gray-50 p-6 rounded-3xl border border-gray-100 transition-all hover:bg-white hover:shadow-lg">
                            <div>
                                <label className="block text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Paga con (Efectivo)</label>
                                <div className="relative mb-3">
                                    <CreditCard className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                                    <input
                                        type="number"
                                        placeholder="Monto exacto por defecto..."
                                        className="w-full bg-white border-2 border-transparent focus:border-indigo-500 rounded-2xl pl-12 pr-4 py-4 text-xl font-black text-gray-800 transition-all outline-none"
                                        value={pagoCon}
                                        onChange={(e) => setPagoCon(e.target.value)}
                                    />
                                </div>
                                <div className="flex gap-2">
                                    <button onClick={() => setPagoCon('')} disabled={carrito.length === 0} className="flex-1 py-1.5 bg-indigo-50 hover:bg-indigo-100 text-indigo-600 text-[10px] font-black uppercase tracking-widest rounded-lg transition-colors disabled:opacity-50">Exacto</button>
                                    <button onClick={() => setPagoCon((Math.ceil(totalFactura / 10) * 10).toString())} disabled={carrito.length === 0} className="flex-1 py-1.5 bg-gray-50 hover:bg-gray-100 text-gray-600 text-[10px] font-black uppercase tracking-widest rounded-lg transition-colors disabled:opacity-50">Redondear 10</button>
                                    <button onClick={() => setPagoCon((Math.ceil(totalFactura / 50) * 50).toString())} disabled={carrito.length === 0} className="flex-1 py-1.5 bg-gray-50 hover:bg-gray-100 text-gray-600 text-[10px] font-black uppercase tracking-widest rounded-lg transition-colors disabled:opacity-50">Billetes Grandes</button>
                                </div>
                            </div>

                            {vuelto > 0 && (
                                <div className="pt-4 animate-in zoom-in-95 fade-in duration-300">
                                    <div className="flex justify-between items-center text-emerald-600 bg-emerald-50 px-5 py-4 rounded-2xl border border-emerald-100 shadow-sm">
                                        <span className="text-sm font-bold uppercase tracking-widest">Su Vuelto:</span>
                                        <span className="text-2xl font-black font-mono tracking-tighter">${vuelto.toFixed(2)}</span>
                                    </div>
                                </div>
                            )}
                        </div>

                        <POSButton
                            variant="primary"
                            className="w-full h-18 text-xl py-6 rounded-3xl mt-8 shadow-2xl flex items-center justify-center gap-3 group/btn"
                            disabled={loading || carrito.length === 0 || !clienteId}
                            onClick={facturar}
                        >
                            {loading ? (
                                <>
                                    <div className="w-6 h-6 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                                    <span>Emitiendo...</span>
                                </>
                            ) : (
                                <>
                                    <span>Completar Venta</span>
                                    <ArrowRight className="group-hover/btn:translate-x-1 transition-transform" />
                                </>
                            )}
                        </POSButton>

                        <p className="text-center text-[10px] text-gray-300 font-bold uppercase tracking-wider mt-6 px-4">
                            Al emitir, se actualizará el stock y se registrará el movimiento de salida automáticamente.
                        </p>
                    </div>

                    {/* Quick Stats / Info Widget */}
                    <div className="bg-gradient-to-br from-indigo-900 to-purple-900 rounded-[32px] p-6 text-white shadow-xl shadow-indigo-200">
                        <div className="flex items-center gap-3 mb-4 opacity-80">
                            <FileText size={20} />
                            <h4 className="text-xs font-black uppercase tracking-widest">Información Tributaria</h4>
                        </div>
                        <ul className="space-y-3">
                            <li className="flex gap-3 items-start">
                                <div className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5 shadow-[0_0_10px_rgba(129,140,248,0.8)]"></div>
                                <p className="text-xs font-medium text-indigo-100 flex-1 leading-relaxed">
                                    Documento respaldado bajo la resolución multi-tenant #{empresa.id}.
                                </p>
                            </li>
                            <li className="flex gap-3 items-start">
                                <div className="w-1.5 h-1.5 rounded-full bg-indigo-400 mt-1.5"></div>
                                <p className="text-xs font-medium text-indigo-100 flex-1 leading-relaxed">
                                    Régimen Simplificado - Empresa: <span className="font-black underline decoration-indigo-500/50">{empresa.nombre}</span>
                                </p>
                            </li>
                        </ul>
                    </div>
                </div>
            </div>

            {/* 📋 Section: Panel de Auditoría Completo */}
            <div className="bg-white rounded-[40px] border border-gray-100 shadow-sm overflow-hidden">
                <div className="px-10 py-8 bg-gray-50/30 flex flex-col md:flex-row md:items-center justify-between gap-4 border-b border-gray-100">
                    <div>
                        <h2 className="text-xl font-black text-gray-900 tracking-tight">Panel de Auditoría</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Control de Facturación · {historicoFacturas.length} facturas emitidas</p>
                    </div>
                    <div className="flex items-center gap-3">
                        {/* Buscador en auditoría */}
                        <div className="relative">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
                            <input
                                type="text"
                                placeholder="Buscar factura, cliente..."
                                value={auditSearch}
                                onChange={e => { setAuditSearch(e.target.value); setAuditPage(1); }}
                                className="pl-9 pr-4 py-2 text-sm border border-gray-200 rounded-xl focus:ring-2 focus:ring-indigo-400 focus:border-indigo-400 outline-none bg-white"
                            />
                        </div>
                        <POSButton variant="ghost" onClick={cargarDatosMaestros}>
                            <RefreshCw size={14} className={loading ? 'animate-spin' : ''} />
                        </POSButton>
                        <div className="text-right">
                            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest leading-none">Total $</p>
                            <p className="text-xl font-black text-indigo-600 font-mono mt-0.5">
                                ${historicoFacturas.reduce((s, f) => s + Number(f.total), 0).toFixed(2)}
                            </p>
                        </div>
                    </div>
                </div>

                {(() => {
                    const filtered = historicoFacturas.filter(f =>
                        !auditSearch ||
                        f.nro_factura?.toLowerCase().includes(auditSearch.toLowerCase()) ||
                        f.cliente_nombre?.toLowerCase().includes(auditSearch.toLowerCase()) ||
                        f.vendedor_nombre?.toLowerCase().includes(auditSearch.toLowerCase())
                    );
                    const totalPages = Math.max(1, Math.ceil(filtered.length / AUDIT_PER_PAGE));
                    const paginated = filtered.slice((auditPage - 1) * AUDIT_PER_PAGE, auditPage * AUDIT_PER_PAGE);

                    return (
                        <>
                            <div className="overflow-x-auto">
                                <table className="w-full text-left whitespace-nowrap">
                                    <thead>
                                        <tr className="bg-gray-50 border-b border-gray-100 text-[10px] font-black text-gray-400 uppercase tracking-widest">
                                            <th className="px-8 py-4"># Factura</th>
                                            <th className="px-8 py-4">Fecha y Hora</th>
                                            <th className="px-8 py-4">Cliente</th>
                                            <th className="px-8 py-4">Vendedor</th>
                                            <th className="px-8 py-4 text-right">Total</th>
                                            <th className="px-8 py-4 text-center">Estado</th>
                                            <th className="px-8 py-4 text-center">Acciones</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-50">
                                        {paginated.length === 0 ? (
                                            <tr>
                                                <td colSpan="7" className="px-8 py-12 text-center text-sm font-bold text-gray-400">
                                                    {auditSearch ? `Sin resultados para "${auditSearch}"` : 'No hay operaciones registradas aún.'}
                                                </td>
                                            </tr>
                                        ) : (
                                            paginated.map(factura => (
                                                <tr key={factura.id} className="hover:bg-indigo-50/20 transition-colors group">
                                                    <td className="px-8 py-4">
                                                        <span className="font-mono font-black text-indigo-600 text-sm">#{factura.nro_factura}</span>
                                                    </td>
                                                    <td className="px-8 py-4 text-sm text-gray-500">
                                                        {factura.fecha_emision
                                                            ? new Date(factura.fecha_emision.endsWith('Z') ? factura.fecha_emision.slice(0, -1) : factura.fecha_emision).toLocaleString('es-AR')
                                                            : '-'}
                                                    </td>
                                                    <td className="px-8 py-4">
                                                        <span className="text-sm font-bold text-gray-800">{factura.cliente_nombre}</span>
                                                    </td>
                                                    <td className="px-8 py-4">
                                                        <span className="text-sm text-gray-500">{factura.vendedor_nombre}</span>
                                                    </td>
                                                    <td className="px-8 py-4 text-right">
                                                        <span className="font-black text-gray-900 font-mono">${Number(factura.total).toFixed(2)}</span>
                                                    </td>
                                                    <td className="px-8 py-4 text-center">
                                                        <span className="inline-flex items-center gap-1 px-2 py-1 rounded-full text-[10px] font-black uppercase tracking-wider bg-emerald-50 text-emerald-600 border border-emerald-100">
                                                            <CheckCircle size={10} /> Emitida
                                                        </span>
                                                    </td>
                                                    <td className="px-8 py-4 text-center">
                                                        <button
                                                            onClick={async () => {
                                                                try {
                                                                    const r = await api.get(`/facturacion/${factura.id}`);
                                                                    setFacturaAnterior(r.data || factura);
                                                                } catch {
                                                                    setFacturaAnterior(factura);
                                                                }
                                                            }}
                                                            className="text-indigo-600 hover:text-white bg-indigo-50 hover:bg-indigo-600 px-3 py-1.5 rounded-lg text-xs font-bold transition-all inline-flex items-center gap-1.5 border border-indigo-100 hover:border-indigo-600"
                                                        >
                                                            <FileText size={13} /> Ver / Imprimir
                                                        </button>
                                                    </td>
                                                </tr>
                                            ))
                                        )}
                                    </tbody>
                                </table>
                            </div>

                            {/* Paginación */}
                            {totalPages > 1 && (
                                <div className="flex items-center justify-between px-8 py-4 border-t border-gray-100 bg-gray-50/30">
                                    <p className="text-xs text-gray-400 font-bold">
                                        Página {auditPage} de {totalPages} · {filtered.length} resultados
                                    </p>
                                    <div className="flex gap-2">
                                        <button
                                            disabled={auditPage === 1}
                                            onClick={() => setAuditPage(p => p - 1)}
                                            className="px-4 py-1.5 text-xs font-bold rounded-lg border border-gray-200 hover:bg-gray-100 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                                        >
                                            ← Anterior
                                        </button>
                                        <button
                                            disabled={auditPage === totalPages}
                                            onClick={() => setAuditPage(p => p + 1)}
                                            className="px-4 py-1.5 text-xs font-bold rounded-lg border border-gray-200 hover:bg-gray-100 disabled:opacity-40 disabled:cursor-not-allowed transition-colors"
                                        >
                                            Siguiente →
                                        </button>
                                    </div>
                                </div>
                            )}
                        </>
                    );
                })()}
            </div>

            {/* Modal Condicionada al final */}
            {renderInvoiceSummary()}

        </div>
    );
};

export default Facturacion;
