import React, { useState } from 'react';
import api from './utils/axiosConfig';
import { toast } from 'react-hot-toast';
import { useAuth } from './context/AuthContext';
import { ArrowRight, Building2, Mail, Lock, User } from 'lucide-react';

const LoginForm = () => {
    const { login } = useAuth();
    const [isLogin, setIsLogin] = useState(true);
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [nombre, setNombre] = useState('');
    const [empresaNombre, setEmpresaNombre] = useState('');
    const [loading, setLoading] = useState(false);

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            if (isLogin) {
                const res = await api.post('/auth/login', { email, password });
                login(res.data);
                if (!res.data.requires_empresa_select) {
                    toast.success('Sesión iniciada correctamente.');
                }
            } else {
                await api.post('/auth/register', { empresaNombre, nombre, email, password });
                toast.success('Empresa registrada. Ahora puedes iniciar sesión.');
                setIsLogin(true);
            }
        } catch (err) {
            const errorMsg = err.response?.data?.error || 'Error en la autenticación';
            toast.error(errorMsg);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-full flex flex-col justify-center py-10 sm:px-6 lg:px-8 bg-[#FAFAFA]">
            <div className="sm:mx-auto sm:w-full sm:max-w-md">
                <div className="flex justify-center">
                    <div className="w-12 h-12 bg-black rounded-xl flex items-center justify-center shadow-md">
                        <span className="text-white font-bold text-xl tracking-tighter">SP</span>
                    </div>
                </div>
                <h2 className="mt-6 text-center text-3xl font-extrabold text-gray-900 tracking-tight">
                    {isLogin ? 'Iniciar Sesión' : 'Crear Cuenta'}
                </h2>
                <p className="mt-2 text-center text-sm text-gray-600">
                    {isLogin ? 'Accede a tu panel de control empresarial' : 'Comienza a gestionar tu negocio hoy mismo'}
                </p>
            </div>

            <div className="mt-8 sm:mx-auto sm:w-full sm:max-w-md animate-fade-in-up">
                <div className="bg-white py-8 px-4 shadow-sm sm:rounded-2xl sm:px-10 border border-gray-100 relative overflow-hidden">
                    {/* Top line accent */}
                    <div className="absolute top-0 left-0 w-full h-1 bg-black"></div>

                    <form className="space-y-5 mt-2" onSubmit={handleSubmit}>
                        {!isLogin && (
                            <div className="space-y-5">
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Empresa</label>
                                    <div className="relative">
                                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                            <Building2 className="h-5 w-5 text-gray-400" />
                                        </div>
                                        <input
                                            type="text"
                                            required
                                            value={empresaNombre}
                                            onChange={(e) => setEmpresaNombre(e.target.value)}
                                            className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-lg focus:ring-black focus:border-black sm:text-sm bg-gray-50/50 hover:bg-gray-50 transition-colors"
                                            placeholder="Nombre de la empresa"
                                        />
                                    </div>
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-gray-700 mb-1">Nombre Completo</label>
                                    <div className="relative">
                                        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                            <User className="h-5 w-5 text-gray-400" />
                                        </div>
                                        <input
                                            type="text"
                                            required
                                            value={nombre}
                                            onChange={(e) => setNombre(e.target.value)}
                                            className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-lg focus:ring-black focus:border-black sm:text-sm bg-gray-50/50 hover:bg-gray-50 transition-colors"
                                            placeholder="Tu nombre y apellido"
                                        />
                                    </div>
                                </div>
                            </div>
                        )}

                        <div>
                            <label className="block text-sm font-medium text-gray-700 mb-1">Correo Electrónico</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Mail className="h-5 w-5 text-gray-400" />
                                </div>
                                <input
                                    type="email"
                                    required
                                    value={email}
                                    onChange={(e) => setEmail(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-lg focus:ring-black focus:border-black sm:text-sm bg-gray-50/50 hover:bg-gray-50 transition-colors"
                                    placeholder="ejemplo@correo.com"
                                />
                            </div>
                        </div>

                        <div>
                            <div className="flex items-center justify-between mb-1">
                                <label className="block text-sm font-medium text-gray-700">Contraseña</label>
                                {isLogin && (
                                    <span className="text-xs font-semibold text-gray-500 hover:text-black cursor-pointer transition-colors block">
                                        ¿Olvidaste tu contraseña?
                                    </span>
                                )}
                            </div>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Lock className="h-5 w-5 text-gray-400" />
                                </div>
                                <input
                                    type="password"
                                    required
                                    value={password}
                                    onChange={(e) => setPassword(e.target.value)}
                                    className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-lg focus:ring-black focus:border-black sm:text-sm bg-gray-50/50 hover:bg-gray-50 transition-colors"
                                    placeholder="••••••••"
                                />
                            </div>
                        </div>

                        <div className="pt-2">
                            <button
                                type="submit"
                                disabled={loading}
                                className="w-full flex justify-center items-center py-2.5 px-4 border border-transparent rounded-lg shadow-sm text-sm font-medium text-white bg-black hover:bg-gray-900 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-black disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                            >
                                {loading ? (
                                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                    </svg>
                                ) : (
                                    <>
                                        {isLogin ? 'Continuar' : 'Registrar'}
                                        <ArrowRight className="ml-2 h-4 w-4" />
                                    </>
                                )}
                            </button>
                        </div>
                    </form>

                    <div className="mt-8">
                        <div className="relative">
                            <div className="absolute inset-0 flex items-center">
                                <div className="w-full border-t border-gray-200" />
                            </div>
                            <div className="relative flex justify-center text-sm">
                                <span className="px-2 bg-white text-gray-500">
                                    {isLogin ? '¿Primera vez?' : '¿Ya tienes cuenta?'}
                                </span>
                            </div>
                        </div>

                        <div className="mt-6 text-center">
                            <button
                                type="button"
                                onClick={() => {
                                    setIsLogin(!isLogin);
                                    setEmail('');
                                    setPassword('');
                                    setNombre('');
                                    setEmpresaNombre('');
                                }}
                                className="text-sm font-semibold text-gray-900 hover:text-gray-700 transition-colors"
                            >
                                {isLogin ? 'Crea una nueva cuenta de empresa' : 'Inicia sesión con tu cuenta existente'}
                            </button>
                        </div>
                    </div>
                </div>
            </div>
            <style dangerouslySetInnerHTML={{
                __html: `
                .animate-fade-in-up {
                    animation: fadeInUp 0.5s ease-out forwards;
                }
                @keyframes fadeInUp {
                    from { opacity: 0; transform: translateY(10px); }
                    to { opacity: 1; transform: translateY(0); }
                }
            `}} />
        </div>
    );
};

export default LoginForm;
