import React, { useState } from 'react';

const ProductForm = ({ onAdd, onUpdate, isModal, closeModal, initialData }) => {
  const [nombre, setNombre] = useState(initialData?.nombre || '');
  const [sku, setSku] = useState(initialData?.sku || '');
  const [descripcion, setDescripcion] = useState(initialData?.descripcion || '');
  const [precio, setPrecio] = useState(initialData?.precio || '');
  const [stock, setStock] = useState(initialData?.stock || '');
  const [categoria, setCategoria] = useState(initialData?.categoria || '');

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!nombre || !precio) return;

    const productData = {
      nombre,
      sku: sku.trim() || null,
      descripcion,
      precio: parseFloat(precio),
      stock: parseInt(stock) || 0,
      categoria
    };

    if (initialData?.id) {
      onUpdate(initialData.id, productData);
    } else {
      onAdd(productData);
    }

    if (!isModal) {
      setNombre('');
      setSku('');
      setDescripcion('');
      setPrecio('');
      setStock('');
      setCategoria('');
    }
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-4">
      {/* Nombre */}
      <div>
        <label className="block text-sm font-medium text-gray-700">Nombre del Producto *</label>
        <input
          type="text"
          required
          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border"
          value={nombre}
          onChange={(e) => setNombre(e.target.value)}
          placeholder="Ej: Laptop Dell XPS 15"
        />
      </div>

      {/* SKU y Categoría en la misma fila */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-gray-700">SKU / Código</label>
          <input
            type="text"
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border font-mono"
            value={sku}
            onChange={(e) => setSku(e.target.value)}
            placeholder="Ej: PRD-001"
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700">Categoría</label>
          <input
            type="text"
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border"
            value={categoria}
            onChange={(e) => setCategoria(e.target.value)}
            placeholder="Ej: Electrónica"
          />
        </div>
      </div>

      {/* Descripción */}
      <div>
        <label className="block text-sm font-medium text-gray-700">Descripción</label>
        <textarea
          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border"
          rows="2"
          value={descripcion}
          onChange={(e) => setDescripcion(e.target.value)}
          placeholder="Descripción del producto (opcional)"
        />
      </div>

      {/* Precio y Stock */}
      <div className="grid grid-cols-2 gap-4">
        <div>
          <label className="block text-sm font-medium text-gray-700">Precio ($) *</label>
          <input
            type="number"
            required
            step="0.01"
            min="0"
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border"
            value={precio}
            onChange={(e) => setPrecio(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-medium text-gray-700">
            {initialData ? 'Stock Actual' : 'Stock Inicial'}
          </label>
          <input
            type="number"
            min="0"
            className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2 border"
            value={stock}
            onChange={(e) => setStock(e.target.value)}
          />
        </div>
      </div>

      <div className="flex items-center justify-end p-4 border-t border-solid border-gray-200 rounded-b mt-4">
        {isModal && (
          <button
            className="text-red-500 background-transparent font-bold uppercase px-6 py-2 text-sm outline-none focus:outline-none mr-1 mb-1 ease-linear transition-all duration-150"
            type="button"
            onClick={closeModal}
          >
            Cancelar
          </button>
        )}
        <button
          className="bg-indigo-600 text-white active:bg-indigo-700 font-bold uppercase text-sm px-6 py-3 rounded shadow hover:shadow-lg outline-none focus:outline-none mr-1 mb-1 ease-linear transition-all duration-150"
          type="submit"
        >
          Guardar Producto
        </button>
      </div>
    </form>
  );
};

export default ProductForm;
